import { cloneDeep, first, get, isDate, isEmpty, map, omit, size } from 'lodash';
import qs from 'qs';
import { useEffect, useState } from 'react';
import { useLocation, useSearchParams } from 'react-router-dom';
// import { useDispatch } from 'store';

import constants from 'src/utils/constants';
import dateHelper from 'src/utils/dateHelper';
import enums from 'src/utils/enums';
import utils from 'src/utils/utils';
// import { snackbarReducerActions } from 'store/reducers/snackbar';

// default options
const defaultValueState = {
	[enums.queryFilter.page]: 1,
	[enums.queryFilter.limit]: 25,
	[enums.queryFilter.sortDirection]: constants.sort.direction.desc
};

const showErrorCount = 5;

const iQueryParam = {
	string: null,
	params: null,
	parsedObject: {}
};

export default function useQueryFilter({
	requiredParams = {},
	defaultParams = {},
	overrideParams = {},
	isMobileFilter = false,
	localStorageKey = null,
	holdInitialize = false
}) {
	// const dispatch = useDispatch();
	const location = useLocation();
	const [searchParams, setSearchParams] = useSearchParams();
	const [queryParam, setQueryParam] = useState(holdInitialize ? iQueryParam : makeQueryString());
	const [isSearchLoading, setIsSearchLoading] = useState(false);

	useEffect(() => {
		// cleanup after page removes from dom
		return () => setSearchParams({});
	}, []);

	function makeQueryString() {
		let string = null;

		// handling or validate search param first
		let parsedJson = validateCommonSearchParams();

		const storageSearchParams = utils.getItemFromStorage(localStorageKey);
		if (storageSearchParams && Object.keys(parsedJson).length === 0) {
			const _storageSearchParams = JSON.parse(storageSearchParams);
			delete _storageSearchParams.search;
			_storageSearchParams.page = 1;
			_storageSearchParams.limit = 25;
			parsedJson = _storageSearchParams;
		}

		if (Object.keys(parsedJson).length === 0) {
			parsedJson = defaultParams;
		}

		// check override object is there then apply it
		if (Object.keys(overrideParams).length > 0) {
			parsedJson = {
				...parsedJson,
				...overrideParams // override the params
			};
		}

		// this function executes only once for initialize
		// below is for mobile only to handle page
		if (isMobileFilter) {
			// if we don't override page so stored page will apply and create bug like
			// page stored as 10 then page applied with skipping previous records to avoid below is
			parsedJson.page = 1;
		}

		// convert object to string for query
		string = getString(parsedJson);

		// then finally set those objects
		return { string, params: searchParams, parsedObject: parsedJson };
	}

	function setObjectToQueryParam(jsonObj) {
		const removeObjects = [];
		let filterState = { ...jsonObj };

		// handle date
		if (filterState.statsPeriod === enums.statsPeriod.customDate) {
			if (filterState.startDate) {
				filterState.startDate = dateHelper.getFromDate(jsonObj.startDate);
			} else {
				removeObjects.push(enums.queryFilter.startDate);
			}

			if (filterState.endDate) {
				filterState.endDate = dateHelper.getToDate(jsonObj.endDate);
			} else {
				removeObjects.push(enums.queryFilter.endDate);
			}

			if (!filterState.startDate && !filterState.endDate) {
				removeObjects.push(enums.queryFilter.statsPeriod);
			}
		} else {
			removeObjects.push(enums.queryFilter.startDate, enums.queryFilter.endDate);
		}

		// handle search
		if (isEmpty(filterState.search)) {
			removeObjects.push(enums.queryFilter.search);
		}

		// handle sortBy
		if (isEmpty(filterState.sortBy)) {
			removeObjects.push(enums.queryFilter.sortBy);
		}

		// handle sortDirection
		if (isEmpty(filterState.sortDirection)) {
			removeObjects.push(enums.queryFilter.sortDirection);
		}

		filterState = omit(filterState, removeObjects);

		// check override object is there then apply it
		if (Object.keys(overrideParams).length > 0) {
			filterState = {
				...filterState,
				...overrideParams // override the params
			};
		}

		return setQueryParam({ string: getString(filterState), params: searchParams, parsedObject: filterState });
	}

	function validateCommonSearchParams() {
		const searchObj = getObject(searchParams.toString());

		// validate all params
		// validate number fields
		map([enums.queryFilter.page, enums.queryFilter.limit], (key) => {
			if (searchObj[key]) {
				if (!isValidNumberField(key)) {
					searchObj[key] = defaultValueState[key];
				}
			}
		});

		// sortDirection
		if (searchObj[enums.queryFilter.sortDirection]) {
			if (![constants.sort.direction.asc, constants.sort.direction.asc].includes(searchObj[enums.queryFilter.sortDirection])) {
				searchObj[enums.queryFilter.sortDirection] = defaultValueState[enums.queryFilter.sortDirection];
			}
		}

		// statsPeriod with startDate and endDate
		if (searchObj[enums.queryFilter.statsPeriod]) {
			const statsPeriod = searchObj[enums.queryFilter.statsPeriod];

			// statsPeriod is customDate
			if (statsPeriod === enums.statsPeriod.customDate) {
				// validate both from date and endDate
				if (searchObj[enums.queryFilter.startDate] && !isDate(searchObj[enums.queryFilter.startDate])) {
					delete searchObj[enums.queryFilter.startDate];
				}

				// validate both from date and endDate
				if (searchObj[enums.queryFilter.endDate] && !isDate(searchObj[enums.queryFilter.endDate])) {
					delete searchObj[enums.queryFilter.endDate];
				}

				// if startDate or endDate not present then remove statsPeriod
				if (!searchObj[enums.queryFilter.endDate] && !searchObj[enums.queryFilter.startDate]) {
					delete searchObj[enums.queryFilter.statsPeriod];
				}
			} else {
				// statsPeriod is shortcut
				if (!constants.statsPeriods.includes(searchObj[enums.queryFilter.statsPeriod])) {
					delete searchObj[enums.queryFilter.statsPeriod];
				}
			}
		}

		// check required value present if not then add
		if (Object.keys(searchObj).length > 0) {
			map(Object.keys(requiredParams), (key) => {
				if (!searchObj[key]) {
					searchObj[key] = requiredParams[key];
				}
			});
		}

		return searchObj;
	}

	function getString(jsonObj) {
		return qs.stringify(jsonObj, { arrayFormat: 'brackets' });
	}

	function getObject(string) {
		const obj = qs.parse(string, {
			arrayFormat: 'brackets',
			ignoreQueryPrefix: true,
			decoder: (str, defaultDecoder) => {
				if (str === 'true') return true;
				if (str === 'false') return false;
				return defaultDecoder(str); // Default behavior for other values
			}
		});

		// qs always returns string even date also
		// parse date here
		if (obj[enums.queryFilter.startDate] && dateHelper.isValidDate(obj[enums.queryFilter.startDate])) {
			obj[enums.queryFilter.startDate] = new Date(obj[enums.queryFilter.startDate]);
		}

		// for also endDate
		if (obj[enums.queryFilter.endDate] && dateHelper.isValidDate(obj[enums.queryFilter.endDate])) {
			obj[enums.queryFilter.endDate] = new Date(obj[enums.queryFilter.endDate]);
		}

		return obj;
	}

	function isValidNumberField(field) {
		const number = searchParams.get(field);
		return !isNaN(number) && Number(number) > 0;
	}

	function storeQueryParsedObject() {
		if (!localStorageKey) {
			return;
		}

		// avoid to store if found source
		if (Object.keys(queryParam.parsedObject).includes(enums.queryFilter.source)) {
			return;
		}

		utils.setItemToStorage(localStorageKey, JSON.stringify(queryParam.parsedObject));
	}

	function showErrors(errors) {
		if (size(errors) === 1) {
			const [key, value] = first(Object.entries(errors));

			const message = `Parameter (${key}): ${value}`;

			// return dispatch(snackbarReducerActions.errorSnackbar({ message }));
		}

		const messages = [];
		map(Object.keys(errors), (key, index) => {
			if (index < showErrorCount) {
				messages.push(`Parameter (${key}): ${get(errors, key)}`);
			}
		});

		// dispatch(snackbarReducerActions.errorSnackbar({ message: messages }));
	}

	const paginationProps = {
		isSearchLoading,
		setIsSearchLoading,

		onClearSearch: () =>
			setObjectToQueryParam({
				...cloneDeep(queryParam.parsedObject),
				page: 1,
				search: ''
			}),

		onSearch: (value) => {
			if (!isEmpty(value)) {
				setIsSearchLoading(true);
			}

			setObjectToQueryParam({
				...cloneDeep(queryParam.parsedObject),
				page: 1,
				search: value
			});
		},

		onSortByChange: (s) =>
			setObjectToQueryParam({
				...cloneDeep(queryParam.parsedObject),
				...utils.getSortParams(s),
			}),

		onRowChange: (event) =>
			setObjectToQueryParam({
				...cloneDeep(queryParam.parsedObject),
				page: 1,
				limit: parseInt(event.target.value)
			}),

		onPageChange: (_, newPage) => {
			setObjectToQueryParam({
				...cloneDeep(queryParam.parsedObject),
				page: newPage + 1
			});
		}
	};

	return {
		queryParam,
		setObjectToQueryParam,
		currentPath: location.pathname,
		currentHash: location.hash,
		getString,
		showErrors,
		storeQueryParsedObject,
		paginationProps
	};
}

/* eslint-disable react-hooks/exhaustive-deps */
import { Button, FormControlLabel, Menu, MenuItem, Stack } from '@mui/material';
import { useEffect, useState } from 'react';
import enums from 'src/utils/enums.js';

import { Iconify } from '../iconify';

import { themeConfig } from 'src/theme';
import { Label } from '../label';
import DateRangePicker from './DateRangePicker';

export default function StyledDurationFilter({
  onDurationChange,
  minDate,
  maxDate,
  resetDuration,
  defaultDuration,
  isDashboard = false
}) {
  const [durationAnchorEl, setDurationAnchorEl] = useState(null);
  const [selectedFilter, setSelectedFilter] = useState(defaultDuration);

  useEffect(() => {
    if (resetDuration) {
      setSelectedFilter(defaultDuration);
    } else {
      setSelectedFilter(selectedFilter);
    }
  }, [selectedFilter, resetDuration]);

  const handleDurationChange = (value) => {
    setSelectedFilter(value);
    if (value === enums.Duration.Between) {
      onDurationChange(value, null, null);
    } else {
      setSelectedFilter(value);
      onDurationChange(value);
    }
    setDurationAnchorEl(null);
  };

  const getDurationName = (durationValue) => {
    switch (durationValue) {
      case enums.Duration.Yesterday:
        return 'Yesterday';
      case enums.Duration.Today:
        return 'Today';
      case enums.Duration.Last7Days:
        return 'Last 7 Days';
      case enums.Duration.CurrentWeek:
        return 'Current Week';
      case enums.Duration.CurrentMonth:
        return 'Current Month';
      case enums.Duration.LastMonth:
        return 'Last Month';
      case enums.Duration.ThreeMonths:
        return 'Last 3 Months';
      case enums.Duration.SixMonths:
        return 'Last 6 Months';
      case enums.Duration.TwelveMonths:
        return 'Last 12 Months';
      case enums.Duration.CurrentYear:
        return 'Current Year';
      case enums.Duration.PriorYear:
        return 'Prior Year';
      case enums.Duration.Between:
        return 'Custom Dates';
      default:
        return '';
    }
  };

  return (
    <>
      <Stack sx={{ flexDirection: { xs: 'column', sm: 'row' } }} spacing={1}>

        <FormControlLabel
          control={
            <Button
              aria-controls="duration-menu"
              color="primary"
              variant="contained"
              aria-haspopup="true"
              sx={{ whiteSpace: 'nowrap' }}
              onClick={(event) => setDurationAnchorEl(event.currentTarget)}
              endIcon={<Iconify icon="mingcute:down-line" />}
            >
              {getDurationName(selectedFilter)}
            </Button>
          }
          label={<Label variant="text"
            sx={{
              color: themeConfig.palette.grey[600], fontSize: 13,
              fontWeight: 600,
              pr: 1
            }}
          >
            Duration Filter
          </Label>}
          labelPlacement="start"
          sx={{ mr: { xs: 0.1, sm: 0.1 } }}
        />
      </Stack>
      <DateRangePicker
        showDateRangePicker={selectedFilter === enums.Duration.Between}
        minDate={minDate}
        maxDate={maxDate}
        onDateChanges={(start, end) => {
          if (selectedFilter === enums.Duration.Between) {
            onDurationChange(enums.Duration.Between, start, end);
          }
        }}
        resetDuration={resetDuration}
      />
      <Menu
        id="duration-menu"
        anchorEl={durationAnchorEl}
        keepMounted
        open={Boolean(durationAnchorEl)}
        onClose={() => setDurationAnchorEl(null)}
      >
        {isDashboard
          ? Object.values(enums.dashboardDuration).map((duration, index) => (
            <MenuItem key={index} onClick={() => handleDurationChange(duration)}>
              {getDurationName(duration)}
            </MenuItem>
          ))
          : Object.values(enums.Duration).map((duration, index) => (
            <MenuItem key={index} onClick={() => handleDurationChange(duration)}>
              {getDurationName(duration)}
            </MenuItem>
          ))
        }
      </Menu>
    </>
  );
}

import Button from '@mui/material/Button';
import { styled } from '@mui/material/styles';
import { Iconify } from 'src/components/iconify';

// ----------------------------------------------------------------------

export const chipProps = { size: 'small', variant: 'soft' };

// ----------------------------------------------------------------------

export function FiltersResult({ sx, onReset, children, totalResults, ...other }) {
  return (
    <ResultRoot sx={sx} {...other}>
      {/* <ResultLabel>
        <strong>{totalResults}</strong>
        <span> results found</span>
      </ResultLabel> */}

      <ResultContent>
        {children}

        <Button
          color="error"
          onClick={onReset}
          startIcon={<Iconify icon="solar:trash-bin-trash-bold" />}
        >
          Clear
        </Button>
      </ResultContent>
    </ResultRoot>
  );
}

// ----------------------------------------------------------------------

const ResultRoot = styled('div')``;

const ResultLabel = styled('div')(({ theme }) => ({
  ...theme.typography.body2,
  marginBottom: theme.spacing(1.5),
  '& span': { color: theme.vars.palette.text.secondary },
}));

const ResultContent = styled('div')(({ theme }) => ({
  flexGrow: 1,
  display: 'flex',
  flexWrap: 'wrap',
  alignItems: 'center',
  gap: theme.spacing(1),
}));

/* eslint-disable react-hooks/exhaustive-deps */
import { zodResolver } from '@hookform/resolvers/zod';
import LoadingButton from '@mui/lab/LoadingButton';
import {
  Avatar,
  Box,
  Button,
  Card,
  Divider,
  IconButton,
  LinearProgress,
  Stack,
  Tooltip,
  Typography,
} from '@mui/material';
import Grid from '@mui/material/Grid2';
import { useBoolean } from 'minimal-shared/hooks';
import { useEffect, useState } from 'react';
import { useForm } from 'react-hook-form';
import { useSelector } from 'react-redux';
import { ConfirmDialog } from 'src/components/custom-dialog';
import { Field, Form } from 'src/components/hook-form';
import { Iconify } from 'src/components/iconify';
import { toast } from 'src/components/snackbar';
import { TableNoData } from 'src/components/table';
import { useParams } from 'src/routes/hooks';
import apiService from 'src/services/ApiService';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';
import { z as zod } from 'zod';

export const noteSchema = zod.object({
  note: zod.string().nullable().optional(),
});

// ----------------------------------------------------------------------

export function NoteSaveView({ noteType }) {
  const { id } = useParams();
  const { loggedInTeacher } = useSelector((state) => state.AuthReducer);

  const [fetchedNotes, setFetchedNotes] = useState([]);
  const [currentNote, setCurrentNote] = useState('');
  const [selectedNoteId, setSelectedNoteId] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  const confirmDialog = useBoolean();
  const defaultValues = {
    note: '',
  };

  const methods = useForm({
    mode: 'onSubmit',
    resolver: zodResolver(noteSchema),
    defaultValues,
  });

  const {
    formState: { isSubmitting },
  } = methods;

  useEffect(() => {
    getNotesByRefId();
  }, [id]);

  const getNotesByRefId = async (showLoader = true) => {
    if (!id) return;

    if (showLoader) setIsLoading(true);
    const { data } = await apiService.getNotesByRefIdAsync(id);
    setFetchedNotes(data);
    if (showLoader) setIsLoading(false);
  };

  const renderConfirmDialog = () => (
    <ConfirmDialog
      open={confirmDialog.value}
      onClose={() => {
        confirmDialog.onFalse();
        setSelectedNoteId(null);
      }}
      title="Delete Note"
      content={<>Are you sure you want to delete this note?</>}
      action={
        <Button variant="contained" color="error" onClick={handleDeleteNote}>
          Delete
        </Button>
      }
    />
  );

  const handleDeleteNote = async () => {
    const { data } = await apiService.deleteNoteAsync(selectedNoteId);
    if (data) {
      toast.success('Note deleted successfully.');
      const filteredData = fetchedNotes.filter((note) => note._id !== selectedNoteId);
      setFetchedNotes(filteredData);
      confirmDialog.onFalse();
      setSelectedNoteId(null);
    }
  };

  const onSubmit = async () => {
    if (!currentNote.trim()) return;

    const payload = {
      type: noteType,
      note: currentNote.trim(),
      refId: id,
      ...(selectedNoteId && { _id: selectedNoteId }),
    };

    const { data } = await apiService.saveNoteAsync(payload);

    if (data) {
      toast.success('Note saved successfully.');
      await getNotesByRefId(false);
      setCurrentNote('');
      setSelectedNoteId(null);
    }
  };

  const renderNoteForm = () => (
    <Grid size={{ xs: 12, md: 12 }}>
      <Form methods={methods} onSubmit={methods.handleSubmit(onSubmit)}>
        <Card sx={{ px: 3, pt: 1 }}>
          <Typography variant="h6" my={1}>
            Add a Note
          </Typography>
          <Divider sx={{ mx: -3 }} />
          <Stack direction="column" spacing={2} pt={2}>
            <Box mb={2} sx={{ rowGap: 3, columnGap: 2, display: 'grid' }}>
              <Field.Text
                multiline
                rows={8}
                maxLength={5000}
                name="note"
                label="Note"
                placeholder="Add a Note..."
                value={currentNote}
                onChange={(e) => setCurrentNote(e.target.value)}
              />
            </Box>

            <Grid item size={{ xs: 12, md: 8 }}>
              <Stack direction="row" spacing={2}>
                <LoadingButton
                  type="submit"
                  variant="contained"
                  color="primary"
                  loading={isSubmitting}
                >
                  Save
                </LoadingButton>

                <Button
                  disabled={isSubmitting}
                  variant="outlined"
                  color="error"
                  onClick={() => setCurrentNote('')}
                >
                  Clear
                </Button>
              </Stack>
            </Grid>

            <Divider sx={{ mx: -3 }} />
          </Stack>
        </Card>
      </Form>
    </Grid>
  );

  const renderNoteList = () => (
    <Grid item size={{ xs: 12, md: 12 }}>
      <Card sx={{ pl: 3, pb: 3, pt: 1 }}>
        <Box sx={{ pr: 2, pt: 2 }}>
          <Stack spacing={2}>
            {fetchedNotes.map((item) => {
              const noteCreatersId = item.createdBy?._id ?? null;
              const isNoteCreator = loggedInTeacher._id === noteCreatersId;

              return (
                <>
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between',
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                      <Avatar
                        sx={{ bgcolor: 'primary.main', color: 'white' }}
                        src={item.createdBy.imagePath}
                      >
                        {item.createdBy.name.given.charAt(0).toUpperCase()}
                        {item.createdBy.name.family.charAt(0).toUpperCase()}
                      </Avatar>
                      <Box sx={{ display: 'flex', flexDirection: 'column' }}>
                        <Typography variant="body1" fontWeight="bold">
                          {item.createdBy.name.given} {item.createdBy.name.family}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          {dateHelper.formatDateTime(item.createdAt)}
                          <Tooltip
                            title={dateHelper.formatDateTime(item.updatedAt)}
                            placement="top"
                            arrow
                            componentsProps={{
                              tooltip: {
                                sx: {
                                  backgroundColor: themeConfig.palette.grey[700],
                                },
                              },
                              arrow: {
                                sx: {
                                  color: themeConfig.palette.grey[700],
                                },
                              },
                            }}
                          >
                            {item.createdAt !== item.updatedAt && ' (edited)'}
                          </Tooltip>
                        </Typography>
                      </Box>
                    </Box>

                    <Box sx={{ display: 'flex', gap: 0 }}>
                      <Tooltip title="Edit note" placement="top" arrow
                        componentsProps={{
                          tooltip: {
                            sx: {
                              backgroundColor: themeConfig.palette.grey[700],
                            },
                          },
                          arrow: {
                            sx: {
                              color: themeConfig.palette.grey[700],
                            },
                          },
                        }}
                      >
                        <span>
                          <IconButton
                            disabled={!isNoteCreator}
                            onClick={() => {
                              setCurrentNote(item.note);
                              setSelectedNoteId(item._id);
                            }}
                          >
                            <Iconify icon="solar:pen-bold" />
                          </IconButton>
                        </span>
                      </Tooltip>

                      <Tooltip title="Delete note" placement="top" arrow
                        componentsProps={{
                          tooltip: {
                            sx: {
                              backgroundColor: themeConfig.palette.grey[700],
                            },
                          },
                          arrow: {
                            sx: {
                              color: themeConfig.palette.grey[700],
                            },
                          },
                        }}
                      >
                        <span>
                          <IconButton
                            color="error"
                            disabled={!isNoteCreator}
                            onClick={() => {
                              setSelectedNoteId(item._id);
                              confirmDialog.onTrue();
                            }}
                          >
                            <Iconify icon="solar:trash-bin-trash-bold" />
                          </IconButton>
                        </span>
                      </Tooltip>
                    </Box>
                  </Box>
                  <Box sx={{ pl: 7 }}>
                    <Typography
                      variant="body1"
                      sx={{ whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
                    >
                      {item.note}
                    </Typography>
                  </Box>
                  <Divider sx={{ mx: -3 }} />
                </>
              );
            })}
          </Stack>
        </Box>
        {renderConfirmDialog()}
      </Card>
    </Grid>
  );

  return (
    <>
      {isLoading ? (
        <Box
          sx={{
            height: '50vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            flexDirection: 'column',
            gap: 2,
          }}
        >
          <Stack alignItems="center" justifyContent="center" sx={{ width: '100%' }}>
            <LinearProgress color="inherit" sx={{ width: '50%', maxWidth: 360 }} />
          </Stack>
        </Box>
      ) : (
        <Grid container spacing={2}>
          {renderNoteForm()}
          {fetchedNotes.length > 0 && (
            renderNoteList()
          )}
        </Grid>
      )}
    </>
  );
}

