import { Box, IconButton, Link, Stack, TableCell, TableRow, Tooltip } from '@mui/material';
import { useBoolean } from 'minimal-shared/hooks';
import { Iconify } from 'src/components/iconify';
import { Label } from 'src/components/label';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';
import enums from 'src/utils/enums';

import ClinicalVisitOverview from './clinicalVisit-overview';
import HomeStudyOverview from './homeStudy-overview';
// ----------------------------------------------------------------------
const statusColors = {
  Planned: 'primary',
  Ordered: 'warning', //Yellow
  'In Progress': 'info', // Purple - #8E33FF
  Completed: 'primary', // Green - #00A76F
  Cancelled: 'error', // Darker red - #B71D18
};

export function ClinicalVisitTableRow({ row, selected, onUpdateRow, type, isPractitionerView = false }) {
  const orgId =
    row.serviceProvider && row.serviceProvider._id
      ? row.serviceProvider._id
      : row.serviceProvider.reference
        ? row.serviceProvider.reference._id
        : '';

  const practitionerName = row.participant && row.participant.name;
  const organizationName =
    row.serviceProvider && row.serviceProvider.name
      ? row.serviceProvider.name
      : row.serviceProvider.reference
        ? row.serviceProvider.reference.name
        : '';
  const organizationAddress =
    row.serviceProvider && row.serviceProvider.contact && row.serviceProvider.contact[0]
      ? row.serviceProvider.contact[0]
      : row.serviceProvider.reference && row.serviceProvider.reference.contact[0];
  const addressLine =
    organizationAddress && organizationAddress.address
      ? `${organizationAddress.address.city}, ${organizationAddress.address.state}-${organizationAddress.address.postalCode}, ${organizationAddress.address.country}`
      : '';
  const contact = row?.participant?.practitionerRole?.[0]?.contact;
  const phone = contact?.[0]?.telecom?.find((c) => c?.system === 'phone')?.value || null;

  const confirmOverView = useBoolean();
  const confirmHomeStudyOverview = useBoolean();

  const renderOverViewDialog = () =>
    confirmOverView.value && (
      <ClinicalVisitOverview
        encounterId={row._id}
        handleClose={confirmOverView.onFalse}
        handleUpdateRow={onUpdateRow}
      />
    );

  const renderHomeStudyOverViewDialog = () =>
    confirmHomeStudyOverview.value && (
      <HomeStudyOverview
        encounterId={row._id}
        handleClose={confirmHomeStudyOverview.onFalse}
        handleUpdateRow={onUpdateRow}
      />
    );

  return (
    <>
      <TableRow hover selected={selected} aria-checked={selected} tabIndex={-1}>

        {isPractitionerView ? (
          <TableCell>
            <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
              <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
                <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>

                  {row.serviceType.coding.code == enums.encounterType['Clinical Study'] ? `In Clinic Visit` : 'Home Study Visit'}

                </Box>
                <Box
                  component="span"
                  sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
                >
                  {dateHelper.formatDateTime(row.createdAt)}
                </Box>
              </Stack>
            </Box>
          </TableCell>)
          : null}

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ flex: '1 1 auto' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                <Link
                  component={row && row.subject ? RouterLink : 'span'}
                  href={
                    row && row.subject
                      ? `${paths.dashboard.patient.view(row.subject._id)}`
                      : undefined
                  }
                  state={{ search: row.device, type: enums.deviceType.implant }}
                  color="inherit"
                  sx={{ cursor: row && row.subject ? 'pointer' : 'default' }}
                >
                  {row.subject && row.subject.name && row.subject.name.family
                    ? `${row.subject.name.given} ${row.subject.name.family}`
                    : '-'}
                </Link>
              </Box>
              {!isPractitionerView && <Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                <Link
                  component={row && row.device ? RouterLink : 'span'}
                  href={row && row.device ? `${paths.dashboard.device.list}` : undefined}
                  state={{ search: row.device, type: enums.deviceType.implant }}
                  color="inherit"
                  sx={{ cursor: row && row.device ? 'pointer' : 'default' }}
                >
                  {row && row.device ? row.device : ''}
                </Link>
              </Box>
              }
            </Stack>
          </Box>
        </TableCell>

        {!isPractitionerView ?
          <TableCell sx={{ verticalAlign: 'top' }}>
            <Stack>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                <Link
                  component={row && row.participant && row.participant._id ? RouterLink : 'span'}
                  href={row && row.participant && row.participant._id
                    ? `${paths.dashboard.practitioner.view(row.participant._id)}`
                    : undefined}
                  color="inherit"
                  sx={{
                    textDecoration: 'none',
                    cursor: row && row.participant && row.participant._id ? 'pointer' : 'default',
                    '&:hover': {
                      textDecoration: row && row.participant && row.participant._id ? 'underline' : 'none',
                    }
                  }}
                >
                  {practitionerName
                    ? practitionerName.prefix
                      ? `${practitionerName.prefix[0]} ${practitionerName.given} ${practitionerName.family}`
                      : `${practitionerName.given} ${practitionerName.family}`
                    : '-'}
                </Link>
              </Box><Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                {phone ? phone : ''}
              </Box>
            </Stack>
          </TableCell>
          : null}

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Stack>
            <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
              <Link
                component={organizationName ? RouterLink : 'span'}
                href={
                  organizationName
                    ? `${paths.dashboard.org.view(orgId)}`
                    : undefined
                }
                color="inherit"
                sx={{ cursor: organizationName ? 'pointer' : 'default' }}
              >
                {organizationName ? `${organizationName}` : '-'}
              </Link>
            </Box>
            {!isPractitionerView ?
              <Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                {addressLine ? `${addressLine}` : ''}
              </Box>
              : null}
          </Stack>
        </TableCell>

        {isPractitionerView ? <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ display: 'flex' }}>
            <Stack sx={{ typography: 'body1' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {addressLine ? `${addressLine}` : ''}
              </Box>
            </Stack>
          </Box>
        </TableCell> : null}

        {!isPractitionerView ? <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ display: 'flex' }}>
            <Stack sx={{ typography: 'body1' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {dateHelper.formatDateTime(row.createdAt)}
              </Box>
            </Stack>
          </Box>
        </TableCell>
          : null}

        <TableCell sx={{ verticalAlign: 'top' }}>
          {type === enums.encounterType['Clinical Study'] ? (
            <Label variant="outlined" color={statusColors[row.status] || 'warning'}>
              {row.status}
            </Label>
          ) : row.homeStudy ? (
            <Label variant="outlined" color={statusColors[row.homeStudy.status] || 'warning'}>
              {row.homeStudy.status}
            </Label>
          ) : row.status ? (
            <Label variant="outlined" color={statusColors[row.status] || 'warning'}>
              {row.status}
            </Label>
          ) : null}
        </TableCell>

        {type == enums.encounterType['Clinical Study'] ||
          (row.serviceType && row.serviceType.coding.code == enums.encounterType['Clinical Study']) ?
          (
            <TableCell sx={{ verticalAlign: 'top' }}>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <Tooltip title="View Details" placement="top" arrow>
                  <IconButton onClick={confirmOverView.onTrue} color={themeConfig.palette.grey[700]}>
                    <Iconify icon="carbon:view-filled" />
                  </IconButton>
                </Tooltip>
                <Tooltip title="Quick Notes" placement="top" arrow>
                  <IconButton
                    color="inherit"
                    component={RouterLink}
                    href={paths.dashboard.clinicalVisit.notes(row._id)}
                    state={{
                      details: `${row.subject.name.given} ${row.subject.name.family}`,
                    }}
                    onClick={() => {
                      localStorage.setItem(
                        'note-details',
                        JSON.stringify(`${row.subject.name.given} ${row.subject.name.family}`)
                      );
                    }}
                  >
                    <Iconify icon="streamline-cyber:pencil-clipboard" />
                  </IconButton>
                </Tooltip>
              </Box>
            </TableCell>
          ) : (
            <TableCell sx={{ verticalAlign: 'top' }}>
              <Box sx={{ display: 'flex' }}>
                <Tooltip title="View Details" placement="top" arrow>
                  <IconButton
                    onClick={confirmHomeStudyOverview.onTrue}
                    color={themeConfig.palette.grey[700]}
                  >
                    <Iconify icon="carbon:view-filled" />
                  </IconButton>
                </Tooltip>
                <Tooltip title="Quick Notes" placement="top" arrow>
                  <IconButton
                    color="inherit"
                    component={RouterLink}
                    href={paths.dashboard.homeStudy.notes(row._id)}
                    state={{
                      details: `${row.subject.name.given} ${row.subject.name.family}`,
                    }}
                    onClick={() => {
                      localStorage.setItem(
                        'note-details',
                        JSON.stringify(`${row.subject.name.given} ${row.subject.name.family}`)
                      );
                    }}
                  >
                    <Iconify icon="streamline-cyber:pencil-clipboard" />
                  </IconButton>
                </Tooltip>
              </Box>
            </TableCell>
          )}
      </TableRow >
      {renderOverViewDialog()}
      {renderHomeStudyOverViewDialog()}
    </>
  );
}

/* eslint-disable react-hooks/exhaustive-deps */
import {
  Box,
  Button,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Divider,
  ListItemText,
  Stack,
  useMediaQuery,
} from '@mui/material';
import { useTheme } from '@mui/material/styles';
import { useEffect, useState } from 'react';
import { Iconify } from 'src/components/iconify';
import { Label, labelClasses } from 'src/components/label';
import apiService from 'src/services/ApiService';
import { themeConfig } from 'src/theme';
import constants from 'src/utils/constants';
import dateHelper from 'src/utils/dateHelper';
import { encounterStatus } from 'src/utils/dropdownData';

import HomeStudyTimelineView from './homeStudy-timeLine-view';

const HomeStudyOverview = ({ encounterId, handleClose, handleUpdateRow }) => {
  const [isLoading, setLoading] = useState(true);
  const [data, setData] = useState([]);
  const theme = useTheme();
  const smUp = useMediaQuery(theme.breakpoints.up('sm'));

  useEffect(() => {
    getHomeStudyByEncounterId();
  }, []);

  const getHomeStudyByEncounterId = async () => {
    setLoading(true);
    const { data } = await apiService.getHomeStudyByEncounterIdAsync(encounterId);
    setData(data);
    setLoading(false);
  };

  const practitioner =
    data && data.performer
      ? `${data.performer.name.prefix?.[0] || ''} ${data.performer.name.given} ${data.performer.name.family}`
      : '';
  const patient =
    data && data.subject ? `${data.subject.name.given} ${data.subject.name.family}` : '';
  const period = data && data.encounter && data.encounter.period ? data.encounter.period : '';
  const organization =
    data &&
      data.encounter &&
      data.encounter.serviceProvider &&
      data.encounter.serviceProvider.reference
      ? data.encounter.serviceProvider.reference
      : '';
  const homeStudy = data && data.homeStudyId ? data.homeStudyId : '';
  const valueAttachment =
    data && data.encounter && data.encounter.valueAttachment ? data.encounter.valueAttachment : '';

  const encounter = data && data.encounter ? data.encounter : '';
  const handleDelete = () => {
    setLoading(true);
    handleClose();
    handleUpdateRow();
    setLoading(false);
  };

  return (
    <>
      <Dialog
        maxWidth={
          (data && (data.studyLog && data.studyLog.length > 0) &&
            (data.encounter && data.encounter?.identifier?.length > 0))
            ? 'lg'
            : 'md'
        }
        fullWidth
        open={true}
      >
        {isLoading ? (
          <>
            <DialogContent>
              <Stack spacing={2} sx={{ typography: 'body2', p: 10, mx: 12 }}>
                <Stack alignItems="center" justifyContent="center" sx={{ width: '100%' }}>
                  <CircularProgress />
                </Stack>
              </Stack>
            </DialogContent>
          </>
        ) : (
          <>
            <DialogTitle>{`${patient}'s Home Study`}</DialogTitle>
            <Box
              mt={-3}
              ml={3}
              mb={2}
              sx={{
                gap: 1,
                display: 'flex',
                flexWrap: 'wrap',
                [`& .${labelClasses.root}`]: {
                  typography: 'caption',
                  color: themeConfig.palette.grey[700],
                },
              }}
            >
              <Label startIcon={<Iconify width={12} icon="solar:clock-circle-outline" />} ml={10}>
                {data && data.homeStudyId && data.homeStudyId.createdAt
                  ? `Ordered at ${dateHelper.formatDate(data.homeStudyId.createdAt)}`
                  : null}
              </Label>

              {period && period.start && period.end ? (
                <Label
                  color="primary"
                  startIcon={<Iconify width={12} icon="solar:clock-circle-outline" />}
                >
                  {dateHelper.getTimeDuration(period.start, period.end)}
                </Label>
              ) : null}
            </Box>
            <Divider />
            <DialogContent>
              <Stack
                divider={
                  <Divider
                    flexItem
                    orientation={smUp ? 'vertical' : 'horizontal'}
                    sx={{ borderStyle: 'dashed' }}
                  />
                }
                sx={{
                  flexDirection: { xs: 'column', sm: 'row' },
                  justifyContent: 'space-between',
                  gap: { xs: 2, sm: 2.2 },
                }}
              >
                <Box
                  sx={{
                    p: 3,
                    gap: 2,
                    display: 'flex',
                    flexDirection: 'column',
                    flex: 1,
                  }}
                >
                  {[
                    {
                      label: 'Organization',
                      value: organization.name,
                      icon: <Iconify icon="bxs:bank" />,
                    },
                    {
                      label: 'Practitioner',
                      value: practitioner,
                      icon: <Iconify icon="fontisto:doctor" />,
                    },
                    {
                      label: 'Study Type',
                      value: homeStudy && homeStudy.studyType ? homeStudy.studyType : '',
                      icon: (
                        <Iconify icon="iconamoon:category-fill" sx={{ width: 20, height: 20 }} />
                      ),
                    },
                    {
                      label: 'Study Duration',
                      value:
                        homeStudy && homeStudy.studyDuration
                          ? `${homeStudy.studyDuration[0].value} ${constants.units[homeStudy.studyDuration[0].unit]}`
                          : '',
                      icon: (
                        <Iconify
                          icon="mingcute:time-duration-fill"
                          sx={{ width: 20, height: 20 }}
                        />
                      ),
                    },
                    ...(homeStudy && homeStudy.studyType === 'Regular Study' ? [{
                      label: 'Data Density',
                      value:
                        homeStudy &&
                          homeStudy.measurementLength &&
                          homeStudy.scanFrequency &&
                          homeStudy.totalMeasurements
                          ? `${homeStudy.measurementLength[0].value} ${constants.units[homeStudy.measurementLength[0].unit]}
                      every ${homeStudy.scanFrequency.value} ${constants.displayUnits[homeStudy.scanFrequency.unit]}
                      (x ${homeStudy.totalMeasurements})`
                          : '',
                      icon: <Iconify icon="game-icons:time-trap" />,
                    }] : []),
                    {
                      label: 'Symptoms and Notes',
                      value:
                        homeStudy && typeof homeStudy.canLogSymptoms === 'boolean'
                          ? homeStudy.canLogSymptoms
                            ? 'Log ON'
                            : 'Log OFF'
                          : '',
                      icon: <Iconify icon="tabler:report-medical" />,
                    },
                  ].map((item) => (
                    <Box key={item.label} sx={{ gap: 1.5, display: 'flex' }}>
                      {item.icon}
                      <ListItemText
                        primary={item.label}
                        secondary={item.value}
                        style={{ height: '4rem' }}
                        primaryTypographyProps={{
                          typography: 'body2',
                          color: themeConfig.palette.grey[700],
                          mb: 1,
                        }}
                        secondaryTypographyProps={{
                          component: 'span',
                          color: 'text.primary',
                          typography: 'subtitle2',
                        }}
                      />
                    </Box>
                  ))}
                </Box>

                {data && data.encounter && data.encounter?.identifier?.length > 0 && (
                  <Box
                    sx={{
                      p: 3,
                      gap: 2,
                      display: 'flex',
                      flexDirection: 'column',
                      flex: 1,
                    }}
                  >
                    {[
                      {
                        label: 'Implant',
                        value: encounter && encounter.device ? encounter.device : '',
                        icon: (
                          <Box
                            component="img"
                            src="/machine.png"
                            alt="Implant"
                            sx={{ width: 20, height: 20 }}
                          />
                        ),
                      },
                      {
                        label: 'Puck',
                        value: encounter && encounter.basedOn ? encounter.basedOn : '',
                        icon: <Iconify icon="fa6-solid:hockey-puck" />,
                      },
                      {
                        label: 'Mobile',
                        value:
                          encounter && encounter.appVersion ? (
                            <>
                              {`${(encounter && encounter.mobileId) || '-'}`}, App Version :{' '}
                              {encounter.appVersion}
                            </>
                          ) : encounter && encounter.mobileId ? (
                            encounter.mobileId
                          ) : (
                            ''
                          ),
                        icon: <Iconify icon="icon-park-outline:chart-line" />,
                      },
                      {
                        label: 'Session',
                        value:
                          data &&
                            data.encounter &&
                            data.encounter.identifier &&
                            data.encounter.identifier[0]
                            ? data.encounter.identifier[0].value
                            : '',
                        icon: <Iconify icon="carbon:mobile-session" />,
                      },
                      {
                        label: 'Start time',
                        value: period?.start ? dateHelper.formatLongDate(period.start) : '',
                        icon: <Iconify icon="solar:clock-circle-bold" />,
                      },
                      {
                        label: 'End time',
                        value: period?.end ? dateHelper.formatLongDate(period.end) : '',
                        icon: <Iconify icon="solar:clock-circle-bold" />,
                      },
                      {
                        label: 'File',
                        value: valueAttachment?.[0]?.title || '',
                        icon: <Iconify icon="icon-park-outline:file-zip" />,
                      },
                    ]
                      .filter((item) => item.label !== 'Data Density' || item.value !== '')
                      .map((item) => (
                        <Box key={item.label} sx={{ gap: 1.5, display: 'flex' }}>
                          {item.icon}
                          <ListItemText
                            style={{ height: '4rem' }}
                            primary={item.label}
                            secondary={item.value}
                            primaryTypographyProps={{
                              typography: 'body2',
                              color: themeConfig.palette.grey[700],
                              mb: 0.5,
                            }}
                            secondaryTypographyProps={{
                              component: 'span',
                              color: 'text.primary',
                              typography: 'subtitle2',
                            }}
                          />
                        </Box>
                      ))}
                  </Box>
                )}

                {Array.isArray(data && data.studyLog) &&
                  data &&
                  data.studyLog &&
                  data.studyLog.length > 0 && (
                    <Box
                      sx={{
                        pr: 3,
                        gap: 2,
                        display: 'flex',
                        flexDirection: 'column',
                        flex: 1,
                      }}
                    >
                      <HomeStudyTimelineView data={data} />
                    </Box>
                  )}
              </Stack>{' '}
            </DialogContent>
            <Divider />
            <DialogActions style={{ justifyContent: 'space-between' }}>
              <Button color="primary" onClick={handleClose} variant="contained">
                Close
              </Button>
              {data && data.encounter && data.encounter.status === encounterStatus[0].value && (
                <Button onClick={handleDelete} variant="outlined" color="error">
                  Delete
                </Button>
              )}
            </DialogActions>
          </>
        )}
      </Dialog>
    </>
  );
};

