            ) : row.type[0] && row.type[0].coding && row.type[0].coding.code === 'Puck' ? (
              <Iconify width={45} icon="fa6-solid:hockey-puck" />
            ) : row.type[0] && row.type[0].coding && row.type[0].coding.code === 'Mobile' ? (
