            </Stack>
          </Box>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ flex: '1 1 auto' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                {row.modelNumber ? `${row.modelNumber}` : ''}
              </Box>
              <Box
                component="span"
