import { Box, Card, CardHeader, Divider, Stack, Typography } from '@mui/material';
import Grid from '@mui/material/Grid2';
import _ from 'lodash';
import { Iconify } from 'src/components/iconify';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';
import { BOOLEAN_DEVICE_OPTIONS, languageOptions } from 'src/utils/dropdownData';

// ----------------------------------------------------------------------

export function DeviceView({ data }) {

  const renderHardwareData = () => {
    if (!data) return null;

    const locationEnabled =
      data.kiosk && data.kiosk.locationEnabled
        ? BOOLEAN_DEVICE_OPTIONS.find((option) => option.value === data.kiosk.locationEnabled).label
        : '';

    return (
      <Card>
        <CardHeader
          title={
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              {data.type[0] && data.type[0].coding && data.type[0].coding.code === 'Kiosk' ? (
                <Iconify width={30} icon="icon-park-outline:chart-line" />
              ) : data.type[0] && data.type[0].coding && data.type[0].coding.code === 'Implant' ? (
                <Box
                  component="img"
                  src="/machine.png"
                  alt="Implant"
                  sx={{ width: 30, height: 30 }}
                />
              ) : data.type[0] && data.type[0].coding && data.type[0].coding.code === 'Puck' ? (
                <Iconify width={30} icon="fa6-solid:hockey-puck" />
              ) : data.type[0] && data.type[0].coding && data.type[0].coding.code === 'Mobile' ? (
                <Iconify width={30} icon="tabler:device-mobile" />
              ) : null}
              <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
                <Box component="span" sx={{ color: 'inherit' }}>
                  Hardware
                </Box>
              </Stack>
            </Box>
          }
        />
        <Box
          sx={{
            p: 3,
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: 2,
            minWidth: 360,
          }}
        >
          <ContactItem label={`Device Unique Id`} value={data.serialNumber} />
          <ContactItem value="" />
          <ContactItem label={'Device Status'} value={`${_.capitalize(data.status)}`} />
          <ContactItem value="" />
          <ContactItem label={'Device Brand'} value={`${_.capitalize(data.manufacturer)}`} />
          <ContactItem value="" />
          <ContactItem label={'Model Number'} value={`${_.capitalize(data.modelNumber)}`} />

          {data && data.osVersion && (
            <>
              <ContactItem value="" />
              <ContactItem label={'System Version'} value={`${_.capitalize(data.osVersion)}`} />
            </>
          )}
          {locationEnabled && (
            <>
              <ContactItem value="" />
              <ContactItem label="Location Enabled" value={`${locationEnabled}`} />
            </>
          )}
        </Box>
      </Card>
    );
  };

  const renderSoftwareData = () => {
    if (!data) return null;
    const language = data.language
      ? languageOptions.find((option) => option.value === data.language)?.label
      : '-';
    return (
      <Card>
        <CardHeader title="Software" />
        <Box
          sx={{
            p: 3,
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: 2,
            minWidth: 360,
          }}
        >
          <ContactItem
            label="App Name"
            value={
              data &&
                data.type &&
                data.type[0] &&
                data.type[0].coding &&
                data.type[0].coding.code &&
                data.type[0].coding.code === 'Mobile'
                ? 'Patient App'
                : 'HydroSense'
            }
          />
          {data && data.appVersion && (
            <>
              <ContactItem label="" value="" />
              <ContactItem label="App Version" value={data.appVersion} />
            </>
          )}
          <ContactItem label="" value="" />
          <ContactItem
            label="Availability Status"
            value={`${_.capitalize(data.availabilityStatus)}`}
          />
          <ContactItem label="" value="" />
          <ContactItem label="Last updated at" value={dateHelper.formatDateTime(data.updatedAt)} />
        </Box>

        {data && data.orgName && (
          <>
            <Divider sx={{ borderStyle: 'dashed' }} />
            <CardHeader title="Organization" />
            <Box
              sx={{
                p: 3,
                display: 'grid',
                gridTemplateColumns: '1fr 1fr',
                gap: 2,
                minWidth: 380,
              }}
            >
              {data.orgName && <ContactItem label="Organization" value={`${data.orgName}`} />}
              {data.orgName && <ContactItem label="" value="" />}
              {data.language && <ContactItem label="Language" value={language} />}
              {data.language && <ContactItem label="" value="" />}
              {data.timezone && <ContactItem label="Timezone" value={`${data.timezone}`} />}
              {data.timezone && <ContactItem label="" value="" />}
            </Box>
          </>
        )}
      </Card>
    );
  };

  const renderConnectivityData = () => {
    if (data && !data.kiosk) return null;

    const kioskData = data && data.kiosk ? data.kiosk : '-';
    const ipAddress =
      ((
        (data &&
          data.conformsTo &&
          Array.isArray(data.conformsTo) &&
          data.conformsTo.find(
            (item) =>
              item &&
              item.specification &&
              item.specification.coding &&
              item.specification.coding.code === 'IPAddress'
          )) ||
        {}
      ).specification &&
        data.conformsTo.find(
          (item) =>
            item &&
            item.specification &&
            item.specification.coding &&
            item.specification.coding.code === 'IPAddress'
        ).specification.coding.display) ||
      '';
    const power =
      data && data.kiosk && data.kiosk.batteryLevel
        ? (data.kiosk.batteryLevel * 100).toFixed(0)
        : '';
    const isCharging = data && data.kiosk ? data.kiosk.bluetoothCharging : '';

    return (
      <Card>
        <CardHeader title="Power" />
        <Box
          sx={{
            p: 3,
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: 2,
            minWidth: 360,
          }}
        >
          {power && (
            <>
              <ContactItem label="Power State" value={`Battery Level at : ${power}%`} />
              <ContactItem label="" value="" />
            </>
          )}
          <ContactItem
            label="Battery Charging"
            value={isCharging ? `Yes currently charging.` : 'Not currently charging'}
          />
        </Box>
        <Divider sx={{ borderStyle: 'dashed' }} />
        <CardHeader title="Connectivity" />
        <Box
          sx={{
            p: 3,
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: 2,
            minWidth: 360,
          }}
        >
          {kioskData.simStatus !== undefined ? (
            <ContactItem label="Sim Status" value={_.capitalize(kioskData.simStatus.toString())} />
          ) : null}
          <ContactItem label="IP Address" value={ipAddress === 'unknown' ? '0.0.0.0' : ipAddress} />
          {kioskData.airplaneMode !== undefined && (
            <ContactItem
              label="Airplane Mode"
              value={_.capitalize(kioskData.airplaneMode.toString())}
            />
          )}
          {kioskData.bluetoothStatus !== undefined && (
            <ContactItem
              label="Bluetooth Status"
              value={_.capitalize(kioskData.bluetoothStatus.toString())}
            />
          )}
        </Box>

        {data && data.kiosk && (
          <>
            <Divider sx={{ borderStyle: 'dashed' }} />
            <CardHeader title="Memory" />
            <Box
              sx={{
                p: 3,
                display: 'grid',
                gridTemplateColumns: '1fr 1fr',
                gap: 2,
                minWidth: 360,
              }}
            >
              {data.kiosk &&
                [
                  { label: 'Total Disk Capacity', value: data.kiosk.totalDiskCapacity },
                  { label: 'Free Disk Capacity', value: data.kiosk.freeDiskCapacity },
                  { label: 'Total Memory', value: data.kiosk.totalMemory },
                  {
                    label: 'Low RAM Device',
                    value:
                      data.kiosk.lowRamDevice !== undefined
                        ? _.capitalize(data.kiosk.lowRamDevice.toString())
                        : undefined,
                  },
                ]
                  .filter((item) => item.value)
                  .map((item) => (
                    <ContactItem key={item.label} label={item.label} value={item.value} />
                  ))}
            </Box>
          </>
        )}
      </Card>
    );
  };

  function ContactItem({ label, value }) {
    return (
      <Box sx={{ display: 'flex', flexDirection: 'column' }}>
        <Typography variant="subtitle2" color={themeConfig.palette.common.black}>
          {label}
        </Typography>
        <Typography variant="body2" color={themeConfig.palette.grey[700]}>
          {value}
        </Typography>
      </Box>
    );
  }

  return (
    <Grid container spacing={3}>
      <>
        {data ? (
          <>
            <Grid size={{ xs: 12, md: 4 }}>
              <Stack spacing={3}>{renderHardwareData()}</Stack>
            </Grid>
            <Grid size={{ xs: 12, md: 4 }}>
              <Stack spacing={3}>{renderSoftwareData()}</Stack>
            </Grid>
            <Grid size={{ xs: 12, md: 4 }}>
              <Stack spacing={3}>{renderConnectivityData()}</Stack>
            </Grid>
          </>
        ) : null}
      </>
    </Grid>
  );
}

