import { useEffect, useState } from 'react';
import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { DashboardContent } from 'src/layouts/dashboard';
import { useParams } from 'src/routes/hooks';
import { paths } from 'src/routes/paths';
import apiService from 'src/services/ApiService';

import { DeviceView } from '../device-view';
import { Box, LinearProgress } from '@mui/material';

export function DeviceDetailView() {
  const { _id } = useParams();
  const [deviceData, setDeviceData] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    getDeviceDataById();
  }, [_id]);

  const getDeviceDataById = async () => {
    setIsLoading(true);
    if (_id) {
      const { data } = await apiService.getDeviceDataByIdAsync(_id);
      setDeviceData(data);
    }
    setIsLoading(false);
  };

  return (
    <>
      {isLoading ? (
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            height: '100%',
            width: '100%',
            pt: 30,
          }}
        >
          <Box sx={{ position: 'fixed', top: 0, left: 0, zIndex: 2001, width: '100%' }}>
            <LinearProgress color="primary" />
          </Box>
        </Box>
      ) :
        (<DashboardContent>
          <CustomBreadcrumbs
            heading="Device Details"
            links={[
              { name: 'Dashboard', href: paths.dashboard.root },
              { name: 'Devices', href: paths.dashboard.device.root },
              {
                name:
                  deviceData &&
                    deviceData.type &&
                    deviceData.type[0] &&
                    deviceData.type[0].coding &&
                    deviceData.type[0].coding.code
                    ? deviceData.type[0].coding.code === 'Kiosk'
                      ? 'Clinician App'
                      : deviceData.type[0].coding.code
                    : '',
              },
            ]}
            sx={{ mb: { xs: 1, md: 1 } }}
          />

          <DeviceView data={deviceData} />
        </DashboardContent>
        )}
    </>
  );
}

