import apiService from 'src/services/ApiService';

import { cloneDeep } from 'lodash';
import useQueryFilter from 'src/components/filter/QueryFilter';
import constants from 'src/utils/constants';
import enums from 'src/utils/enums';
import { DeviceTableRow } from '../device-table-row';
import { DeviceTableToolbar } from '../device-table-toolbar';

// ----------------------------------------------------------------------

const TABLEHEAD = [
  { id: 'serialNumber', label: 'Device Details', width: '18%' },
  { id: 'owner.name', label: 'Organization', width: '17%', sortBy: false },
  { id: 'manufactureDate', label: 'Manufacturer', width: '12%' },
  { id: 'modelNumber', label: 'Model Details', width: '15%' },
  { id: 'updatedAt', label: 'Last Updated By', width: '16%' },
  { id: 'availabilityStatus', label: 'Availability Status', width: '14%' },
  { id: '', label: 'Action', width: '10%', sortBy: false, sx: { paddingLeft: '55px' } },
];

const requiredParams = {
  [enums.queryFilter.page]: 1,
  [enums.queryFilter.limit]: 25,
  [enums.queryFilter.sortDirection]: constants.sort.direction.desc,
  [enums.queryFilter.sortBy]: 'updatedAt'
};

const defaultParams = {
  [enums.queryFilter.page]: 1,
  [enums.queryFilter.limit]: 25,
  [enums.queryFilter.sortDirection]: constants.sort.direction.desc,
  [enums.queryFilter.sortBy]: 'updatedAt',
  [enums.queryFilter.status]: 'active'
};

const getDefaultParams = (locationParams) => {
  const _defaultParams = cloneDeep(defaultParams);

  if (locationParams.search) {
    _defaultParams.search = locationParams.search;
  }

  if (locationParams.type) {
    _defaultParams.type = locationParams.type;
  }

  if (locationParams.orgId) {
    _defaultParams.owner = locationParams.orgId;
  }

  return _defaultParams;
};

export function DeviceListView() {
  const table = useTable();
  const location = useLocation();
  const navigation = useNavigate();
  const locationParams = location.state || {};

  const {
    type: deviceTypeFilter = '',
    orgId: ownerFilter = '',
    search: searchFilter = '',
  } = locationParams;

  const [isLoading, setIsLoading] = useState(false);
  const [tableData, setTableData] = useState([]);

  const [totalRecords, setTotalRecords] = useState(0);

  const { queryParam, setObjectToQueryParam, storeQueryParsedObject, showErrors, paginationProps }
    = useQueryFilter({ requiredParams, defaultParams: getDefaultParams(locationParams) });


  const filters = useSetState({
    search: queryParam.parsedObject.search || searchFilter,
    status: queryParam.parsedObject.status || 'active',
    type: queryParam.parsedObject.type || deviceTypeFilter,
    owner: queryParam.parsedObject.owner || ownerFilter,
  });

  useEffect(() => {
    if (queryParam.string) {
      navigation(`/dashboard/device?${queryParam.string}`, { replace: true });
      getDeviceList();
    }
  }, [queryParam.string]);

  const getDeviceList = async () => {
    setIsLoading(true);

    const response = await apiService.getDeviceListAsync(queryParam.parsedObject);
    const { data } = response;
    if (data) {
      
      setTableData(data.data);
      setTotalRecords(data.totalRecords || data.data.length);
    } else if (errors) {
      showErrors(errors);
    }
    paginationProps.setIsSearchLoading(false);
    setIsLoading(false);
  };

  const handleFilterChange = (filterDetail) =>
    setObjectToQueryParam({
      ...queryParam.parsedObject,
      ...filterDetail,
      page: 1,
    });

  const handleSort = (property) => {
    const newOrder = table.orderBy === property && table.order === 'asc' ? 'desc' : 'asc';
    table.setOrder(newOrder);
    table.setOrderBy(property);
    const _queryParamObj = cloneDeep(queryParam.parsedObject);
    _queryParamObj.sortBy = property;
    _queryParamObj.sortDirection = newOrder;
    setObjectToQueryParam(_queryParamObj);
  };

  return (
    <>
      <DashboardContent>
        <CustomBreadcrumbs
          heading="Manage Devices"
          links={[
            { name: 'Dashboard', href: paths.dashboard.root },
            { name: 'Devices', href: paths.dashboard.device.list }
          ]}
          action={
            <Button
              component={RouterLink}
              href={paths.dashboard.device.new}
              variant="contained"
              color="primary"
              startIcon={<Iconify icon="mingcute:add-line" />}
            >
              New Device
            </Button>
          }
          sx={{ mb: { xs: 1, md: 1 } }}
        />
        <Card>
          <DeviceTableToolbar filters={filters} onFilterChange={handleFilterChange} />
          <Paper sx={{ width: '100%', overflow: 'hidden' }}>
            <TableContainer sx={{ height: 'calc(100vh - 46vh)' }}>
              <Box sx={{ position: 'relative' }}>
                <Table
                  stickyHeader={true}
                  aria-label="sticky table"
                  size={table.dense ? 'small' : 'medium'}
                  sx={{ minWidth: 960 }}
                >
                  <TableHeadCustom
                    order={queryParam.parsedObject.sortDirection || table.order}
                    orderBy={queryParam.parsedObject.sortBy || table.orderBy}
                    headCells={TABLEHEAD}
                    rowCount={tableData.length}
                    numSelected={table.selected.length}
                    onSort={handleSort}
                  />
                  {isLoading ? (
                    <TableBody>
                      <TableRow>
                        <TableCell colSpan={TABLEHEAD.length}>
                          <Box
                            sx={{
                              display: 'flex',
                              justifyContent: 'center',
                              alignItems: 'center',
                              height: '100%',
                              width: '100%',
                            }}
                          >
                            <Stack
                              alignItems="center"
                              justifyContent="center"
                              sx={{ width: '100%' }}
                            >
                              <LinearProgress
                                color="inherit"
                                sx={{ width: '50%', maxWidth: 360 }}
                              />
                            </Stack>
                          </Box>
                        </TableCell>
                      </TableRow>
                    </TableBody>
                  ) : (
                    <TableBody>
                      {tableData.map((row) => (
                        <DeviceTableRow
                          key={row._id}
                          row={row}
                          selected={table.selected.includes(row._id)}
                        />
                      ))}

                      <TableEmptyRows
                        height={table.dense ? 56 : 56 + 20}
                        emptyRows={emptyRows(table.page, table.rowsPerPage, tableData.length)}
                      />
                      <TableNoData
                        label="No devices found. Please try again later or adjust your search."
                        notFound={tableData.length <= 0}
                      />
                    </TableBody>
                  )}
                </Table>
              </Box>
            </TableContainer>
            <TablePaginationCustom
              page={Number(queryParam.parsedObject.page - 1)}
              count={totalRecords}
              rowsPerPage={Number(queryParam.parsedObject.limit)}
              onPageChange={paginationProps.onPageChange}
              onRowsPerPageChange={paginationProps.onRowChange}
              onChangeDense={table.onChangeDense}
            />
          </Paper>
        </Card>
      </DashboardContent>
    </>
  );
}

