  //     >
  //       <Avatar src={avatarUrl} />
  //       <Box sx={{ overflow: 'hidden' }}>
  //         <Typography
  //           variant="subtitle2"
  //           noWrap
  //           sx={{
  //             fontWeight: 600,
  //             color: isHovered ? 'primary.main' : 'text.primary',
  //             transition: 'color 0.3s ease',
  //           }}
  //         >
  //           {name}
  //         </Typography>
  //         <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }} noWrap>
  //           {email}
  //         </Typography>
  //       </Box>
  //     </Box>
  //   );
  // }

  const renderContacts = () => {
    if (!info) return null;

    const contactName = info.organizationData
      ? `${info.organizationData.organizationId.contact[0].name.given} ${info.organizationData.organizationId.contact[0].name.family}`
      : '';
    const phone = `${info.organizationData.organizationId.contact[0].telecom[0].value}`;
    const email = `${info.organizationData.organizationId.contact[0].telecom[1].value}`;
    const timeZone = `${info.organizationData.timeZone}`;
    const timeout = `${info.organizationData.timeout}`;
    const idleSleepTime = `${info.organizationData.idleSleepTime}`;
    const language = languageOptions.find(
      (option) => option.value === info.organizationData.language
    )?.label;
    const dateFormat = `${info.organizationData.dateFormat}`;

    return (
      <Card>
        <CardHeader title="Contact" />
        <Divider sx={{ borderStyle: 'dashed' }} />
        <Box
          sx={{
            p: 3,
            gap: 1,
            display: 'flex',
            flexDirection: 'column',
            minWidth: 360,
          }}
        >
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: -2 }}>
            <Iconify width={25} icon="ic:sharp-person" />
            <ContactItem label={contactName} />
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: -1 }}>
            <Iconify width={22} icon="ic:sharp-phone" />
            <ContactItem value={phone} />
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: -1 }}>
            <Iconify width={22} icon="clarity:email-solid" />
            <ContactItem value={email} />
          </Box>
        </Box>
        <CardHeader title="Settings" sx={{ mt: -5 }} />
        <Divider sx={{ borderStyle: 'dashed' }} />
        <Scrollbar sx={{ minHeight: 150 }}>
          <Box
            sx={{
              p: 3,
              display: 'grid',
              gridTemplateColumns: '1fr 1fr',
              gap: 1,
              minWidth: 360,
            }}
          >
            <ContactItem label="Timeout" value={`${timeout} min`} mt={-2} />
            <ContactItem label="Idle Sleep Time" value={`${idleSleepTime} min`} mt={-2} />
            <ContactItem label="Language" value={language} mt={-1} />
            <ContactItem label="Date Format" value={dateFormat} mt={-1} />
            <ContactItem label="Timezone" value={timeZone} mt={-1} />
          </Box>
        </Scrollbar>
      </Card>
    );
  };

  function ContactItem({ label, value, mt = 0 }) {
    return (
      <Box sx={{ mt: mt, display: 'flex', flexDirection: 'column' }}>
        <Typography variant="subtitle2" color="text.primary">
          {label}
        </Typography>
        <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }}>
          {value}
        </Typography>
      </Box>
    );
  }

  return (
    <Grid container spacing={3}>
      <Grid size={{ xs: 12, md: 4 }}>
        <Stack spacing={3}>
          {renderFollows()}
          {renderAboutOrg()}
        </Stack>
      </Grid>
      <Grid size={{ xs: 12, md: 4 }}>
        {partOf ? <Stack spacing={3} >{renderPartOf()}</Stack> : null}
        {info && info.relatedOrgs && info.relatedOrgs.length ? (
          <Stack spacing={3} mt={partOf ? 2 : ''}>{renderRelatedOrgs()}</Stack>
        ) : null}
        {/* {info && info.patients && info.patients.length ? (
          <Stack
            spacing={3}
            sx={{
              mt:
                (info.partOf && info.partOf.length) || (info.relatedOrgs && info.relatedOrgs.length)
                  ? 3
                  : 0,
            }}
          >
            {renderPatients()}
          </Stack>
        ) : null} */}
      </Grid>
      <Grid size={{ xs: 12, md: 4 }}>
        <Stack spacing={3}>{renderContacts()}</Stack>
      </Grid>
    </Grid>
  );
}

import { Avatar, Box, Card, IconButton, Stack, Typography } from '@mui/material';
import { EmptyContent } from 'src/components/empty-content';
import { Iconify } from 'src/components/iconify';
import { themeConfig } from 'src/theme';

export function OrgPractitioners({ practitioners }) {
  return (
    <>
      {practitioners && practitioners.length > 0 ? (
        <>
          <Box
            sx={{
              gap: 3,
              display: 'grid',
              gridTemplateColumns: { xs: 'repeat(1, 1fr)', md: 'repeat(3, 1fr)' },
            }}
          >
            {practitioners.map((practitioner) => {

              const practitionerName = practitioner.practitionerDetails.name ? practitioner.practitionerDetails.name : '';
              const practitionerDisplayName = practitionerName
                ? practitionerName.prefix
                  ? `${practitionerName.prefix[0]} ${practitionerName.given} ${practitionerName.family}`
                  : `${practitionerName.given} ${practitionerName.family}`
                : '-';

              const practitionerPhoto = practitioner.practitionerDetails.photo[0]?.url ?? '';
              const phone = practitioner.contact[0].telecom.find((item) => item.system === 'phone');
              const email = practitioner.contact[0].telecom.find((item) => item.system === 'email');
              return (
                <Card key={practitioner._id} sx={{ p: 2 }}>
                  <Box sx={{ display: 'flex', gap: 2 }}>
                    <Avatar
                      alt={practitionerPhoto}
                      src={practitionerPhoto}
                      sx={{ width: 48, height: 48 }}
                    />

                    <Stack spacing={0.5} justifyContent="center">
                      <Typography fontWeight={600}>{practitionerDisplayName}</Typography>
                      <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }}>
                        {practitioner.code[0].coding.code}
                      </Typography>
                    </Stack>
                  </Box>

                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 3,
                      mt: 1.5,
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                      <IconButton size="small" sx={{ borderRadius: 1, p: 0.5 }}>
                        <Iconify width={18} icon="solar:phone-bold" />
                      </IconButton>
                      <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }}>
                        {phone.value}
                      </Typography>
                    </Box>

                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                      <IconButton size="small" sx={{ borderRadius: 1, p: 0.5 }}>
                        <Iconify width={18} icon="clarity:email-solid" />
                      </IconButton>
                      <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }}>
                        {email.value}
                      </Typography>
                    </Box>
                  </Box>
                </Card>
              );
            })}
          </Box>
        </>
      ) : (
        <EmptyContent
          title={'No Practitioners found. Please try again later.'}
          filled
          sx={[{ py: 10 }]}
        />
      )}
    </>
  );
}

