import { zodResolver } from '@hookform/resolvers/zod';
import { LoadingButton } from '@mui/lab';
import {
  Autocomplete, Box, Button, Card, Divider, FormControl,
  MenuItem, Paper, Stack, TextField, Typography
} from '@mui/material';
import Grid from '@mui/material/Grid2';
import { styled } from '@mui/material/styles';
import { Controller, useForm } from 'react-hook-form';
import { useNavigate } from 'react-router';
import { timezones } from 'src/assets/data/timezones';
import { Field, Form, schemaHelper } from 'src/components/hook-form';
import { LoadingScreen } from 'src/components/loading-screen';
import { toast } from 'src/components/snackbar';
import { useParams, useRouter } from 'src/routes/hooks';
import { paths } from 'src/routes/paths';
import apiService from 'src/services/ApiService';
import constants from 'src/utils/constants';
import dateHelper from 'src/utils/dateHelper';
import { z as zod } from 'zod';

import { useEffect, useState } from 'react';
import {
  dateFormatOptions, languageOptions, typeOptions, US_States,
} from '../../utils/dropdownData';

const Item = styled(Paper)(({ theme }) => ({
  backgroundColor: '#fff',
  ...theme.typography.body2,
  paddingBottom: theme.spacing(2),
  textAlign: 'center',
  color: theme.palette.text.secondary,
  ...theme.applyStyles('dark', {
    backgroundColor: '#1A2027',
  }),
}));

const currentTimeZone = dateHelper.getCurrentTimeZone();
const isUSTimezone = dateHelper.isUSTimezone();

export const OrgSchema = zod.object({
  language: zod.string().min(1, { message: 'Language is required.' }),
  dateFormat: zod.string().min(1, { message: 'Date Format is required.' }),
  timeZone: zod.string().min(1, { message: 'Timezone is required.' }),
  alias: zod.array(zod.string().trim().min(1, { message: 'Code is required.' })),
  name: zod.string().trim().min(1, { message: 'Organization Name is required.' }),
  adminName: zod.object({
    family: zod.string().trim().min(1, { message: 'First Name is required.' }),
    given: zod.string().trim().min(1, { message: 'Last Name is required.' }),
  }),
  address: zod.object({
    line: zod.array(zod.string().nullable().optional()),
    country: schemaHelper.nullableInput(zod.string().min(1, { message: 'Country is required.' }), {
      message: 'Country is required.',
    }),
    state: zod.string().min(1, { message: 'State/Province is required.' }),
    city: zod.string().min(1, { message: 'City is required.' }),
    postalCode: zod.string().min(1, { message: 'Zip/Postal code is required.' }),
  }),
  typeCode: zod.optional(zod.string()),
  icpUnitsType: zod.string().min(1, { message: 'ICP Unit Type is required.' }),
  email: zod
    .string()
    .min(1, { message: 'Email Address is required.' })
    .email({ message: 'Email must be a valid email address.' }),
  phone: zod.string().min(12, { message: 'Phone is required.' }),
  timeout: zod
    .number({ coerce: true }, { message: 'Timeout must be a number.' })
    .int({ message: 'Timeout must be a whole number (no decimals allowed).' })
    .min(1, { message: 'Timeout must be at least 1 minute.' })
    .optional(),
  idleSleepTime: zod
    .number({ coerce: true }, { message: 'Idle Sleep Time must be a number.' })
    .int({ message: 'Idle Sleep Time must be a whole number (no decimals allowed).' })
    .min(1, { message: 'Idle Sleep Time must be at least 1 minute.' })
    .optional(),
  endpoint: zod
    .array(
      zod.object({
        reference: zod
          .string()
          .url({ message: 'EMR Link must be a valid URL.' })
          .optional()
          .or(zod.literal('')),
      })
    )
    .optional(),
  note: zod.string().nullable().optional(),
  partOf: zod.string().nullable().optional(),
});

export function OrgSaveForm() {
  const router = useRouter();
  const navigate = useNavigate();
  const { _id } = useParams();
  const [ownerOptions, setOwnerOptions] = useState([]);


  const defaultValues = {
    language: constants.defaultLang,
    dateFormat: constants.dateFormat,
    timeZone: isUSTimezone ? currentTimeZone : constants.defaultTimeZone,
    alias: [''],
    name: '',
    typeCode: 'prov', //TODO,
    endpoint: [{ reference: '' }],
    adminName: {
      family: '',
      given: '',
    },
    email: '',
    phone: '',
    address: {
      line: ['', ''],
      city: '',
      state: '',
      postalCode: '',
      country: constants.defaultCountryCode,
    },
    timeout: 1,
    idleSleepTime: 10,
    note: '',
    icpUnitsType: '',
    partOf: null,
  };

  const methods = useForm({
    mode: 'onSubmit',
    resolver: zodResolver(OrgSchema),
    defaultValues: async () => getOrgDataById(),
  });
  const {
    setError,
    handleSubmit,
    getValues,
    formState: { isSubmitting, isLoading },
  } = methods;

  useEffect(() => {
    const getParentOrgOptions = async () => {
      const response = await apiService.getParentOrgOptionsAsync();
      if (response?.data && Array.isArray(response.data)) {
        setOwnerOptions(response.data);
      }
    };
    getParentOrgOptions();
  }, []);

  const getOrgDataById = async () => {
    if (_id) {
      const { data } = await apiService.getOrgDataByIdAsync(_id);
      const typeCode = data.type && data.type[0].coding.code ? data.type[0].coding.code : 'prov';
      return { ...data, typeCode };
    } else {
      return defaultValues;
    }
  };

  const onSubmit = handleSubmit(async (data) => {
    const payload = {
      _id: _id,
      ...data,
      type: [],
      note: data.note === '' ? null : data.note,
    };

    if (
      Array.isArray(payload.address?.line) &&
      payload.address.line.every((line) => line?.trim() === '')
    ) {
      payload.address.line = [];
    }

    if (data.typeCode) {
      payload.type.push({ coding: { code: data.typeCode } });
      delete payload.typeCode;
    }

    const response = await apiService.saveOrgAsync(payload);
    if (response.data) {
      toast.success(
        _id ? 'Organization updated successfully.' : 'Organization created successfully.'
      );
      router.push({
        pathname: paths.dashboard.org.list,
      });
    } else if (response.errors) {
      console.log(response.errors, " ==> response.errors");
      response.errors.map((error) => {
        setError(error.param, { message: error.msg });
      });
    }
  });

  return (
    <>
      {isLoading ? (
        <LoadingScreen />
      ) : (
        <Form methods={methods} onSubmit={onSubmit}>
          <Grid container spacing={2}>
            <Grid size={{ xs: 12, md: 8 }}>
              <Card sx={{ p: 2 }}>
                <Typography variant="h6">Organization Details</Typography>
                <Grid container pt={1} spacing={2}>
                  <Grid size={{ xs: 12, md: 4 }}>
                    <Item>
                      <Field.Text maxLength={50} name="alias[0]" label="Code" />
                    </Item>
                  </Grid>
                  <Grid size={{ xs: 12, md: 8 }}>
                    <Item>
                      <Field.Text maxLength={100} name="name" label="Organization Name" />
                    </Item>
                  </Grid>
                </Grid>
                <Box
                  sx={{
                    rowGap: 3,
                    columnGap: 2,
                    display: 'grid',
                    gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                  }}
                >
                  <FormControl fullWidth>
                    <Controller name="partOf"
                      control={methods.control}
                      render={({ field }) => (
                        <Autocomplete
                          fullWidth
                          options={ownerOptions}
                          getOptionLabel={(option) => (option && option.name ? option.name : '')}
                          value={ownerOptions.find(option => option._id === field.value) || null}
                          onChange={(_, newValue) => field.onChange(newValue ? newValue._id : null)}
                          renderInput={(params) => <TextField {...params} label="Parent Organization" />}
                          renderOption={(props, option) => (
                            <li {...props} key={option._id}>
                              {option.name}
                            </li>
                          )}
                        />
                      )}
                    />
                  </FormControl>

                  <FormControl fullWidth>
                    <Field.Select name="typeCode" label="Type">
                      {typeOptions.map((typeOption) => (
                        <MenuItem key={typeOption.value} value={typeOption.value}>
                          {typeOption.label}
                        </MenuItem>
                      ))}
                    </Field.Select>
                  </FormControl>
                </Box>
                <Divider sx={{ mx: -3, mt: 2 }} />
                <Typography variant="h6" sx={{ py: 1 }}>
                  Primary Contact Details
                </Typography>
                <Box
                  sx={{
                    rowGap: 3,
                    columnGap: 2,
                    display: 'grid',
                    gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                  }}
                >
                  <Field.Text maxLength={50} name="adminName.given" label="First Name" />
                  <Field.Text maxLength={50} name="adminName.family" label="Last Name" />
                  <Field.Phone
                    name="phone"
                    label="Phone Number"
                    country={getValues('address.country')}
                  />
                  <Field.Text name="email" label="Email Address" />
                </Box>
                <Divider sx={{ mx: -3, mt: 2 }} />
                <Typography variant="h6" sx={{ py: 1 }}>
                  Address Details
                </Typography>
                <Box
                  sx={{
                    rowGap: 3,
                    columnGap: 2,
                    display: 'grid',
                    gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                  }}
                >
                  <Field.Text maxLength={20} name="address.line[0]" label="Address" />
                  <Field.Text
                    maxLength={20}
                    name="address.line[1]"
                    label="Apartment, Suite, etc."
                  />
                  <Field.Text maxLength={20} name="address.city" label="City" />
                  <Field.Select maxLength={10} name="address.state" label="State/Province">
                    {US_States.map((option) => (
                      <MenuItem key={option.value} value={option.value}>
                        {option.label}
                      </MenuItem>
                    ))}
                  </Field.Select>

                  <Field.CountrySelect
                    fullWidth
                    name="address.country"
                    label="Country"
                    placeholder="Choose a Country"
                  />
                  <Field.Text maxLength={10} name="address.postalCode" label="Zip/Postal Code" />
                </Box>
                <Stack direction="column" spacing={2} mt={2}>
                  <Box
                    sx={{
                      rowGap: 3,
                      columnGap: 2,
                      display: 'grid',
                    }}
                  >
                    <Field.Text
                      multiline
                      rows={3}
                      maxLength={500}
                      name="note"
                      label="Note"
                      placeholder="Note..."
                    />
                  </Box>
                </Stack>
              </Card>
            </Grid>
            <Grid size={{ xs: 12, md: 4 }}>
              <Card sx={{ p: 2 }}>
                <Typography variant="h6" sx={{ pb: 2 }}>
                  Organization Settings
                </Typography>
                <Box
                  sx={{
                    rowGap: 3,
                    display: 'grid',
                    columnGap: 2,
                    gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(1, 1fr)' },
                  }}
                >
                  <Field.Select name="language" label="Language">
                    {languageOptions.map((option) => (
                      <MenuItem key={option.value} value={option.value}>
                        {option.label}
                      </MenuItem>
                    ))}
                  </Field.Select>

                  <Field.Select name="dateFormat" label="Date Format">
                    {dateFormatOptions.map((option) => (
                      <MenuItem key={option.value} value={option.value}>
                        {option.label}
                      </MenuItem>
                    ))}
                  </Field.Select>

                  <Field.Select name="timeZone" label="Timezone">
                    {timezones.US.map((zone) => (
                      <MenuItem key={zone.value} value={zone.value}>
                        {zone.label}
                      </MenuItem>
                    ))}
                  </Field.Select>

                  <Field.Text
                    type="number"
                    slotProps={{ inputLabel: { shrink: true } }}
                    maxLength={4}
                    name="timeout"
                    label="Timeout (in mins)"
                  />

                  <Field.Text
                    type="number"
                    slotProps={{ inputLabel: { shrink: true } }}
                    maxLength={4}
                    name="idleSleepTime"
                    label="Idle Sleep Time (in mins)"
                  />

                  <Box pl={1}>
                    <Field.RadioGroup
                      row
                      name="icpUnitsType"
                      label="ICP Unit Type"
                      options={[
                        { value: 'mmHg', label: 'mmHg' },
                        { value: 'cmH2O', label: 'cmH2O' },
                      ]}
                    />
                  </Box>

                  <Field.Text maxLength={50} name="endpoint[0].reference" label="EMR Link" sx={{ mb: 1 }} />

                </Box>
              </Card>
            </Grid>
          </Grid>
          <Stack direction="row" spacing={2} sx={{ mt: 2 }}>
            <LoadingButton type="submit" variant="contained" color="primary" loading={isSubmitting}>
              {_id ? 'Save Changes' : 'Create Organization'}
            </LoadingButton>
            <Button
              disabled={isLoading}
              variant="outlined"
              color="error"
              onClick={() => {
                navigate(-1);
              }}
            >
              Cancel
            </Button>
          </Stack>
        </Form>
      )}
    </>
  );
}

import { Box, Button, IconButton, Link, Stack, TableCell, TableRow, Tooltip } from '@mui/material';
import { useBoolean } from 'minimal-shared/hooks';
import { ConfirmDialog } from 'src/components/custom-dialog';
import { Iconify } from 'src/components/iconify';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';
import { typeOptions } from 'src/utils/dropdownData';

// ----------------------------------------------------------------------

export function OrgTableRow({ row, selected, profileHref, onDeleteRow }) {
  const confirmDialog = useBoolean();
  const contact = row.contact[0];
  const type = row.type[0].coding.code;
  const addressLine1 =
    contact.address.line[0] && contact.address.line[1]
      ? contact.address.line.join(', ')
      : contact.address.line[0]
        ? contact.address.line[0]
        : contact.address.line[1];
  const addressLine2 = `${contact.address.city}, ${contact.address.state}-${contact.address.postalCode}, ${contact.address.country}`;
  const phone = contact.telecom.find((c) => c.system === 'phone').value;
  const renderConfirmDialog = () => (
    <ConfirmDialog
      open={confirmDialog.value}
      onClose={confirmDialog.onFalse}
      title="Delete Organization"
      content={`Are you sure want to delete ${row.name}?`}
      action={
        <Button variant="contained" color="error" onClick={onDeleteRow}>
          Delete
        </Button>
      }
    />
  );

  return (
    <>
      <TableRow hover selected={selected} aria-checked={selected} tabIndex={-1}>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                <Link
                  component={RouterLink}
                  href={profileHref}
                  state={{ organization: row }}
                  color="inherit"
                  sx={{ cursor: 'pointer' }}
                >
                  {row.name}
                </Link>
              </Box>
              <Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                {typeOptions.find((option) => option.value === type).label || ''}
              </Box>
            </Stack>
          </Box>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Stack>
            {addressLine1 && (
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                {addressLine1}
              </Box>
            )}
            <Box
              component="span"
              sx={{
                color: addressLine1 ? themeConfig.palette.grey[700] : 'inherit',
                typography: addressLine1 ? 'Subtitle2' : 'body1',
              }}
            >
              {addressLine2}
            </Box>
          </Stack>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ flex: '1 1 auto' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                {`${contact.name.given} ${contact.name.family}`}
              </Box>
              <Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                {phone}
              </Box>
            </Stack>
          </Box>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ flex: '1 1 auto' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1', }}>
                {row.updatedBy && row.updatedBy.reference && row.updatedBy.reference.name ? `${row.updatedBy.reference.name.given} ${row.updatedBy.reference.name.family}` : ''}
              </Box>
              <Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                {row.updatedAt ? dateHelper.formatDateTime(row.updatedAt) : ''}
              </Box>
            </Stack>
          </Box>
        </TableCell>

        {/* Action Buttons */}
        {row.status === 'Active' && (
          <TableCell>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <Tooltip title="View Details" placement="top" arrow>
                <IconButton
                  component={RouterLink}
                  href={profileHref}
                >
                  <Iconify icon="carbon:view-filled" />
                </IconButton>
              </Tooltip>

              <Tooltip title="Quick Edit" placement="top" arrow>
                <IconButton
                  component={RouterLink}
                  href={paths.dashboard.org.edit(row._id)}
                  color="primary"
                >
                  <Iconify icon="solar:pen-bold" />
                </IconButton>
              </Tooltip>

              <Tooltip title="Quick Notes" placement="top" arrow>
                <IconButton
                  color="inherit"
                  component={RouterLink}
                  state={{ details: row.name }}
                  href={paths.dashboard.org.notes(row._id)}
                  onClick={() => {
                    localStorage.setItem('note-details', JSON.stringify(`${row.name}`));
                  }}
                >
                  <Iconify icon="streamline-cyber:pencil-clipboard" />
                </IconButton>
              </Tooltip>

              <Tooltip title="Quick Delete" placement="top" arrow>
                <IconButton color="error" onClick={() => confirmDialog.onTrue()}>
                  <Iconify icon="solar:trash-bin-trash-bold" />
                </IconButton>
              </Tooltip>
            </Box>
          </TableCell>
        )}
      </TableRow>

      {renderConfirmDialog()}
    </>
  );
}

import { Button, Stack, Typography } from '@mui/material';
import Box from '@mui/material/Box';
import Card from '@mui/material/Card';
import Tab from '@mui/material/Tab';
import Tabs from '@mui/material/Tabs';
import { useCallback, useState } from 'react';
import { _userFeeds } from 'src/_mock';
import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { Iconify } from 'src/components/iconify';
import { Label } from 'src/components/label';
import { DashboardContent } from 'src/layouts/dashboard';
