import { usePathname, useSearchParams } from 'src/routes/hooks';
import { paths } from 'src/routes/paths';
import { useNavigate } from 'react-router';
import { typeOptions } from 'src/utils/dropdownData';

import { OrgCover } from '../org-cover';
import { OrgDevices } from '../org-devices';
import { OrgHome } from '../org-home';
import { OrgPractitioners } from '../org-practitioners';

// ----------------------------------------------------------------------

const TAB_PARAM = 'tab';

export function OrgProfileView({ organization, orgId }) {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const navigate = useNavigate();
  const selectedTab = searchParams.get(TAB_PARAM) ?? '';
  const [searchDevices, setSearchDevices] = useState('');

  const organizationData =
    organization && organization.organizationData && organization.organizationData.organizationId
      ? organization.organizationData.organizationId
      : '';
  const contact = organizationData && organizationData.contact ? organizationData.contact[0] : null;
  const address = contact && contact.address ? contact.address : null;
  const type =
    organizationData &&
      organizationData.type[0] &&
      organizationData.type[0].coding &&
      organizationData.type[0].coding.code
      ? organizationData.type[0].coding.code
      : '';

  const typeName = typeOptions.find((option) => option.value === type);
  const orgType = (typeName && typeName.label) || '';

  const FullAddress = [
    address && address.line && address.line[0] ? address.line[0] : '',
    address && address.line && address.line[1] ? address.line[1] : '',
    address && address.city ? address.city : '',
    address && address.state
      ? address.postalCode
        ? `${address.state}-${address.postalCode}`
        : address.state
      : '',
    address && address.country ? address.country : '',
  ]
    .filter(Boolean)
    .join(', ');

  const handleSearchDevices = useCallback((event) => {
    setSearchDevices(event.target.value);
  }, []);

  const createRedirectPath = (currentPath, query) => {
    const queryString = new URLSearchParams({ [TAB_PARAM]: query }).toString();
    return query ? `${currentPath}?${queryString}` : currentPath;
  };

  const NAV_ITEMS = [
    {
      value: '',
      label: 'About Organization',
      icon: <Iconify width={24} icon="solar:user-id-bold" />,
    },
    {
      value: 'practitioners',
      label: (
        <Stack direction="row" spacing={1}>
          <Typography>Practitioners</Typography>
          <Label color="primary" variant="filled">
            {organization && organization.practitioners.length}
          </Label>
        </Stack>
      ),
      icon: <Iconify width={24} icon="healthicons:doctor-male-outline" />,
    },
    {
      value: 'devices',
      label: (
        <Stack direction="row" spacing={1}>
          <Typography>Devices</Typography>
          <Label color="warning" variant="filled">
            {organization && organization.devices.length}
          </Label>
        </Stack>
      ),
      icon: <Iconify width={24} icon="carbon:mobile" />,
    },
  ];

  const onNavigateCreateOrg = () => {
    navigate('/dashboard/org/new?orgId=' + orgId, {
      state: { owner: organization.organizationData.organizationId.name },
    });
  };

  return (
    <DashboardContent>
      <CustomBreadcrumbs
        heading="Organization Profile"
        links={[
          { name: 'Dashboard', href: paths.dashboard.root },
          { name: 'Organizations', href: paths.dashboard.org.list },
          {
            name:
              organization &&
                organization.organizationData &&
                organization.organizationData.organizationId
                ? organization.organizationData.organizationId.name
                : '',
          },
        ]}
        // action={
        //   organization &&
        //   organization.organizationData &&
        //   organization.organizationData.organizationId &&
        //   !organization.organizationData.organizationId.partOf && (
        //     <Button
        //       onClick={onNavigateCreateOrg}
        //       variant="contained"
        //       sx={{
        //         mt: 0.5,
        //         fontWeight: 'bold',
        //         textTransform: 'none',
        //       }}
        //       color="primary"
        //       startIcon={<Iconify icon="mingcute:add-line" />}
        //     >
        //       New Related Organization
        //     </Button>
        //   )
        // }
        sx={{ mb: { xs: 1, md: 1 } }}
      />

      <Card sx={{ mb: 3, height: 190 }}>
        <OrgCover
          name={
            organization &&
              organization.organizationData &&
              organization.organizationData.organizationId
              ? organization.organizationData.organizationId.name
              : ''
          }
          type={orgType}
          address={FullAddress}
        />

        <Box
          sx={{
            width: 1,
            bottom: 0,
            zIndex: 9,
            px: { md: 3 },
            display: 'flex',
            position: 'absolute',
            bgcolor: 'background.paper',
            justifyContent: { xs: 'center', md: 'flex-end' },
          }}
        >
          <Tabs value={selectedTab}>
            {NAV_ITEMS.map((tab) => (
              <Tab
                component={RouterLink}
                key={tab.value}
                value={tab.value}
                icon={tab.icon}
                label={tab.label}
                iconPosition={tab.iconPosition}
                href={createRedirectPath(pathname, tab.value)}
              />
            ))}
          </Tabs>
        </Box>
      </Card>

      {selectedTab === '' && <OrgHome info={organization} posts={_userFeeds} />}

      {selectedTab === 'practitioners' && (
        <OrgPractitioners practitioners={organization.practitioners} />
      )}

      {selectedTab === 'devices' && organization?.devices ? (
        <OrgDevices
          devices={organization.devices}
          searchDevices={searchDevices}
          onSearchDevices={handleSearchDevices}
        />
      ) : null}
    </DashboardContent>
  );
}

