import { Box, LinearProgress, MenuItem, Stack, TextField } from '@mui/material';
import Grid from '@mui/material/Grid2';
import { useTheme } from '@mui/material/styles';
import dayjs from 'dayjs';
import { useEffect, useState } from 'react';
import { Controller, useForm } from 'react-hook-form';
import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import StyledDurationFilter from 'src/components/filter/StyledDurationFilter';
import { Form } from 'src/components/hook-form';
import { svgColorClasses } from 'src/components/svg-color';
import { DashboardContent } from 'src/layouts/dashboard';
import apiService from 'src/services/ApiService';
import dateHelper from 'src/utils/dateHelper';
import { filterType } from 'src/utils/dropdownData';
import enums from 'src/utils/enums';

import { AppNotificationChart } from '../../app-notification-chart';
import { AppActiveDevicesGraph } from '../app-active-devices-graph';
import { AppBarGraph } from '../app-bar-graph';
import { AppVisitsTypeGraph } from '../app-visitsType-graph';
import { AppWidget } from '../app-widget';

// ----------------------------------------------------------------------

export function OverviewAppView() {
  const theme = useTheme();
  const [isLoading, setIsLoading] = useState(false);
  const [statisticsData, setStatisticsData] = useState([]);
  const [activeDeviceStatistics, setActiveDeviceStatistics] = useState([]);
  const [activePractitionerStatistics, setActivePractitionerStatistics] = useState([]);
  const [encounterStatistics, setEncounterStatistics] = useState([]);
  const [activePatientStatistics, setActivePatientStatistics] = useState([]);
  const [activeOrgStatistics, setActiveOrgStatistics] = useState([]);
  const [isMonthlyDisabled, setIsMonthlyDisabled] = useState(false);

  const [payload, setPayload] = useState({
    org: '',
    duration: enums.Duration.TwelveMonths,
    startDate: null,
    endDate: null,
    filterType: enums.typeFilter.monthly,
    timezone: dateHelper.getCurrentTimeZone(),
  });

  useEffect(() => {
    if (
      payload.duration === enums.Duration.Between &&
      payload.startDate &&
      payload.endDate
    ) {
      const diff = dayjs(payload.endDate).diff(dayjs(payload.startDate), 'day');
      if (diff < 30) {
        if (payload.filterType !== enums.typeFilter.weekly) {
          setPayload((prev) => ({
            ...prev,
            filterType: enums.typeFilter.weekly,
          }));
        }
        setIsMonthlyDisabled(true);
      } else {
        setIsMonthlyDisabled(false);
      }
    } else {
      setIsMonthlyDisabled(false);
    }
    // eslint-disable-next-line
  }, [payload.startDate, payload.endDate, payload.duration]);

  useEffect(() => {
    if (payload.duration === enums.Duration.Between) {
      if (!payload.startDate || !payload.endDate) {
        return;
      }
    }
    getDashboardStatistics();
  }, [payload]);

  const getDashboardStatistics = async () => {
    setIsLoading(true);
    const { data } = await apiService.getDashboardStatisticsAsync(payload);

    if (data) {
      setStatisticsData(data);
    }

    if (data.getActiveDeviceStatistics) {
      setActiveDeviceStatistics(data.getActiveDeviceStatistics);
    }

    if (data.getActivePractitionerStatistics) {
      setActivePractitionerStatistics(data.getActivePractitionerStatistics);
    }

    if (data.getEncounterStatistics) {
      setEncounterStatistics(data.getEncounterStatistics);
    }

    if (data.getActivePatientStatistics) {
      setActivePatientStatistics(data.getActivePatientStatistics);
    }

    if (data.getActiveOrgStatistics) {
      setActiveOrgStatistics(data.getActiveOrgStatistics);
    }
    setIsLoading(false);
  };

  const handleDurationChange = (duration, start, end) => {
    let newPayload = { ...payload, duration };

    if (duration === enums.Duration.Between) {
      newPayload.startDate = start;
      newPayload.endDate = end;

      if (start && end) {
        const diff = dayjs(end).diff(dayjs(start), 'day');
        if (diff < 30) {
          newPayload.filterType = enums.typeFilter.weekly;
          setIsMonthlyDisabled(true);
        } else {
          setIsMonthlyDisabled(false);
        }
      }
    } else {
      newPayload.startDate = null;
      newPayload.endDate = null;
      setIsMonthlyDisabled(false);
    }

    setPayload(newPayload);
  };

  const methods = useForm({
    defaultValues: payload,
  });

  const handleFilterChange = (filterDetail) => {
    // Prevent setting to monthly if disabled
    if (
      filterDetail.filterType === enums.typeFilter.monthly &&
      isMonthlyDisabled
    ) {
      return;
    }

    if (filterDetail.filterType === enums.typeFilter.yearly) {
      alert('Yearly summary is currently unavailable due to insufficient data.');
      return;
    }
    setPayload((prev) => ({
      ...prev,
      ...filterDetail,
    }));
  };

  const activePractitionerCategory =
    payload.filterType === enums.typeFilter.monthly
      ? dateHelper.convertMonthNumbersToName(
        activePractitionerStatistics.summaryPeriod,
        activePractitionerStatistics.yearDate
      )
      : dateHelper.getWeeklyDateRanges(
        activePractitionerStatistics.summaryPeriod,
        activePractitionerStatistics.yearDate
      );

  const activeDeviceCategory =
    payload.filterType === enums.typeFilter.monthly
      ? dateHelper.convertMonthNumbersToName(
        activeDeviceStatistics.summaryPeriod,
        activeDeviceStatistics.yearDate
      )
      : dateHelper.getWeeklyDateRanges(
        activeDeviceStatistics.summaryPeriod,
        activeDeviceStatistics.yearDate
      );

  const activeVisitsCategory =
    payload.filterType === enums.typeFilter.monthly
      ? dateHelper.convertMonthNumbersToName(
        encounterStatistics.summaryPeriod,
        encounterStatistics.yearDate
      )
      : dateHelper.getWeeklyDateRanges(
        encounterStatistics.summaryPeriod,
        encounterStatistics.yearDate
      );

  const activePatientCategory =
    payload.filterType === enums.typeFilter.monthly
      ? dateHelper.convertMonthNumbersToName(
        activePatientStatistics.summaryPeriod,
        activePatientStatistics.yearDate
      )
      : dateHelper.getWeeklyDateRanges(
        activePatientStatistics.summaryPeriod,
        activePatientStatistics.yearDate
      );

  const activeOrgCategory =
    payload.filterType === enums.typeFilter.monthly
      ? dateHelper.convertMonthNumbersToName(
        activeOrgStatistics.summaryPeriod,
        activeOrgStatistics.yearDate
      )
      : dateHelper.getWeeklyDateRanges(
        activeOrgStatistics.summaryPeriod,
        activeOrgStatistics.yearDate
      );

  const totalVisits =
    statisticsData &&
      statisticsData.getEncounterStatistics &&
      statisticsData.getEncounterStatistics.totalClinicalVisits
      ? statisticsData.getEncounterStatistics.totalClinicalVisits
      : 0;

  const totalStudy =
    statisticsData &&
      statisticsData.getEncounterStatistics &&
      statisticsData.getEncounterStatistics.totalHomeStudy
      ? statisticsData.getEncounterStatistics.totalHomeStudy
      : 0;

  const notificationData =
    payload.filterType === enums.typeFilter.weekly
      ? {
        name: 'Weekly',
        categories: [
          '2 Jun, 25',
          '9 Jun, 25',
          '16 Jun, 25',
          '23 Jun, 25',
        ],
        data: [
          { name: 'Email', data: [20, 34, 48, 65] },
          { name: 'SMS', data: [10, 34, 13, 26] },
          { name: 'App-to-App', data: [10, 14, 13, 16] },
          { name: 'Other', data: [5, 12, 6, 7] },
        ],
      }
      : {
        name: 'Monthly',
        categories: ['Jan - 25', 'Feb - 25', 'Mar - 25', 'Apr - 25', 'May - 25', 'Jun - 25', 'Jul - 25'],
        data: [
          { name: 'Email', data: [10, 34, 13, 56, 77, 88, 89] },
          { name: 'SMS', data: [20, 30, 15, 54, 70, 83, 90] },
          { name: 'App-to-App', data: [15, 38, 14, 58, 68, 89, 94] },
          { name: 'Other', data: [25, 37, 18, 59, 75, 80, 79] },
        ],
      };

  return (
    <>
      {isLoading ? (
        <DashboardContent>
          <CustomBreadcrumbs
            heading="Dashboard"
            action={
              <>
                <Form methods={methods} onSubmit={handleFilterChange}>
                  <Grid item xs={12} sx={{ mt: -1 }}>
                    <Stack
                      direction={{ xs: 'column', sm: 'row' }}
                      py={2}
                      sx={{
                        alignItems: { xs: 'flex-start', sm: 'center' },
                        justifyContent: 'space-between',
                        gap: 2,
                      }}
                    >
                      <Stack
                        direction={'row'}
                        spacing={2}
                        sx={{
                          alignItems: { xs: 'flex-start', sm: 'center' },
                          justifyContent: { xs: 'flex-start', sm: 'space-between' },
                          gap: { xs: 2, sm: 2 },
                        }}
                      >
                        <StyledDurationFilter
                          onDurationChange={handleDurationChange}
                          resetDuration={true}
                          defaultDuration={payload.duration}
                          minDate={'2024-01-01'}
                          maxDate={dayjs().format('MM-DD-YYYY')}
                          isDashboard={true}
                        />
                        <Controller
                          name="filterType"
                          control={methods.control}
                          render={({ field }) => (
                            <TextField
                              {...field}
                              select
                              sx={{ width: { xs: '150px', sm: '150px' } }}
                              label="Summary Type"
                              size="small"
                              value={payload.filterType}
                              onChange={(e) => {
                                field.onChange(e);
                                handleFilterChange({ filterType: e.target.value });
                              }}
                              SelectProps={{
                                MenuProps: {
                                  slotProps: {
                                    paper: {
                                      sx: { maxHeight: 220 },
                                    },
                                  },
                                },
                              }}
                            >
                              {filterType.map((option) => (
                                <MenuItem
                                  key={option.value}
                                  value={option.value}
                                  disabled={
                                    option.value === enums.typeFilter.monthly &&
                                    isMonthlyDisabled
                                  }
                                >
                                  {option.label}
                                </MenuItem>
                              ))}
                            </TextField>
                          )}
                        />

                      </Stack>
                    </Stack>
                    <Box sx={{ position: 'fixed', top: 0, left: 0, zIndex: 2001, width: '100%' }}>
                      <LinearProgress color="primary" />
                    </Box>
                  </Grid>
                </Form>
              </>
            }
            sx={{ mb: { xs: 3, md: 2.5 } }}
          />
        </DashboardContent>
      ) : (
        <DashboardContent>
          <CustomBreadcrumbs
            heading="Dashboard"
            action={
              <>
                <Form methods={methods} onSubmit={handleFilterChange}>
                  <Grid item xs={12} sx={{ mt: -1 }}>
                    <Stack
                      direction={{ xs: 'column', sm: 'row' }}
                      py={2}
                      sx={{
                        alignItems: { xs: 'flex-start', sm: 'center' },
                        justifyContent: 'space-between',
                        gap: 2,
                      }}
                    >
                      <Stack
                        direction={'row'}
                        spacing={2}
                        sx={{
                          alignItems: { xs: 'flex-start', sm: 'center' },
                          justifyContent: { xs: 'flex-start', sm: 'space-between' },
                          gap: { xs: 2, sm: 2 },
                        }}
                      >
                        <StyledDurationFilter
                          onDurationChange={handleDurationChange}
                          resetDuration={true}
                          defaultDuration={payload.duration}
                          minDate={'2024-01-01'}
                          maxDate={dayjs().format('MM-DD-YYYY')}
                          isDashboard={true}
                        />
                        <Controller
                          name="filterType"
                          control={methods.control}
                          render={({ field }) => (
                            <TextField
                              {...field}
                              select
                              sx={{ width: { xs: '150px', sm: '150px' } }}
                              label="Summary Type"
                              size="small"
                              value={payload.filterType}
                              onChange={(e) => {
                                field.onChange(e);
                                handleFilterChange({ filterType: e.target.value });
                              }}
                              SelectProps={{
                                MenuProps: {
                                  slotProps: {
                                    paper: {
                                      sx: { maxHeight: 220 },
                                    },
                                  },
                                },
                              }}
                            >
                              {filterType.map((option) => (
                                <MenuItem
                                  key={option.value}
                                  value={option.value}
                                  disabled={
                                    option.value === enums.typeFilter.monthly &&
                                    isMonthlyDisabled
                                  }
                                >
                                  {option.label}
                                </MenuItem>
                              ))}
                            </TextField>
                          )}
                        />
                      </Stack>
                    </Stack>
                  </Grid>
                </Form>
              </>
            }
            sx={{ mb: { xs: 1, md: 1 } }}
          />
          <Grid container spacing={3} mt={-1}>
            <Grid size={{ xs: 12, md: 3 }}>
              <AppWidget title="Organizations" icon="bxs:bank" total={statisticsData.totalOrganizations}
                sx={{
                  bgcolor: 'warning.dark',
                  [`& .${svgColorClasses.root}`]: { color: 'warning.light' },
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 3 }}>
              <AppWidget title="Devices" icon="carbon:mobile" total={statisticsData.totalDevices}
                sx={{
                  bgcolor: 'info.dark', [`& .${svgColorClasses.root}`]: { color: 'info.light' },
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 3 }}>
              <AppWidget title="In Clinic Visits" total={totalVisits} icon="healthicons:syringe-vaccine" />
            </Grid>
            <Grid size={{ xs: 12, md: 3 }}>
              <AppWidget title="Home Studies" total={totalStudy}
                icon="fa6-solid:person-shelter"
                chart={{ series: 75, colors: [theme.vars.palette.error.light, theme.vars.palette.error.main], }}
                sx={{
                  bgcolor: 'error.dark',
                  [`& .${svgColorClasses.root}`]: { color: 'error.light' },
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 6, lg: 6 }}>
              <AppBarGraph title={`Active Organizations : ${statisticsData.totalOrganizations}`}
                chart={{
                  categories: activeOrgCategory,
                  series: [{ name: 'Organizations', data: activeOrgStatistics.orgs }],
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 6, lg: 6 }}>
              <AppBarGraph title={`Active Practitioners : ${statisticsData.totalPractitioners}`}
                chart={{
                  categories: activePractitionerCategory,
                  series: [
                    { name: 'Practitioners', data: activePractitionerStatistics.practitioners },
                  ],
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 6, lg: 6 }}>
              <AppActiveDevicesGraph title="Active Devices"
                chart={{
                  categories: activeDeviceCategory,
                  series: [
                    { name: 'Implant', data: activeDeviceStatistics.implant, },
                    { name: 'Puck', data: activeDeviceStatistics.puck, },
                    { name: 'Clinician App', data: activeDeviceStatistics.kiosk, },
                    { name: 'Mobile', data: activeDeviceStatistics.mobile, },
                  ],
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 6, lg: 6 }}>
              <AppBarGraph title={`Active Patients : ${statisticsData.totalPatients}`}
                chart={{
                  categories: activePatientCategory,
                  series: [{ name: 'Patients', data: activePatientStatistics.patients }],
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 6, lg: 6 }}>
              <AppVisitsTypeGraph title="Visits Over Time"
                totalVisits={totalVisits} totalStudy={totalStudy}
                chart={{
                  categories: activeVisitsCategory,
                  series: [
                    { name: 'In Clinic Visits', data: encounterStatistics.clinicalVisits, },
                    { name: 'Home Studies', data: encounterStatistics.homeStudy, },
                  ],
                }}
              />
            </Grid>
            <Grid size={{ xs: 12, md: 6, lg: 6 }}>
              <AppNotificationChart title="Notifications" chart={notificationData} />
            </Grid>
          </Grid>
        </DashboardContent>
      )}
    </>
  );
}

/* eslint-disable react-hooks/exhaustive-deps */
import { Box, LinearProgress, MenuItem, Stack, TextField } from '@mui/material';
import Grid from '@mui/material/Grid2';
import dayjs from 'dayjs';
import { useEffect, useState } from 'react';
import { Controller, useForm } from 'react-hook-form';
import { CardSummary } from 'src/components/cards/card-summary';
import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { EmptyContent } from 'src/components/empty-content';
import StyledDurationFilter from 'src/components/filter/StyledDurationFilter';
import { Form } from 'src/components/hook-form';
import { CONFIG } from 'src/global-config';
import { ComponentLayout } from 'src/layouts/components/layout';
import { DashboardContent } from 'src/layouts/dashboard';
import { useParams } from 'src/routes/hooks';
import { paths } from 'src/routes/paths';
import apiService from 'src/services/ApiService';
import dateHelper from 'src/utils/dateHelper';
import enums from 'src/utils/enums';

import PatientTimelineView from './patient-timeline-component';
// ----------------------------------------------------------------------

export function PatientDetailView() {
  const { _id } = useParams();
  const [isLoading, setIsLoading] = useState(false);
  const [data, setData] = useState([]);
  const [orgOptions, setOrgOptions] = useState([]);
  const [practitionerOptions, setPractitionerOptions] = useState([]);

  const [payload, setPayload] = useState({
    _id: _id,
    serviceProvider: '',
    performer: '',
    duration: enums.Duration.TwelveMonths,
    startDate: null,
    endDate: null,
    timezone: dateHelper.getCurrentTimeZone(),
  });

  useEffect(() => {
    if (payload.duration === enums.Duration.Between) {
      if (!payload.startDate || !payload.endDate) {
        return;
      }
    }
    getPatientDetail();
  }, [payload]);

  useEffect(() => {
    const fetchData = async () => {
      const [orgsData, practitionersData] = await Promise.all([
        apiService.getOrgOptionsAsync(),
        apiService.getPractitionerOptionsAsync(),
      ]);
      if (orgsData) {
        setOrgOptions(orgsData.data);
      }

      if (practitionersData) {
        setPractitionerOptions(practitionersData.data);
      }
    };

    fetchData();
  }, []);

  const getPatientDetail = async () => {
    setIsLoading(true);
    if (payload._id) {
      const response = await apiService.getPatientDetailAsync(payload);
      const { data } = response;
      setData(data);
    }
    setIsLoading(false);
  };

  const handleFilterChange = (filterDetail) => {
    setPayload((prev) => ({
      ...prev,
      ...filterDetail,
    }));
  };

  const handleDurationChange = (duration, start, end) => {
    if (duration === enums.Duration.Between) {
      setPayload((prevState) => ({
        ...prevState,
        duration,
        startDate: start,
        endDate: end,
      }));
    } else {
      setPayload((prevState) => ({
        ...prevState,
        duration,
        startDate: null,
        endDate: null,
      }));
    }
  };

  const methods = useForm({
    defaultValues: payload,
  });

  const SECTION_DATA = [
    {
      name: 'Clinical-Visit timeline',
      component: <PatientTimelineView data={data} />,
    },
  ];

  const getOrganizationHref = (data) => {
    const orgId =
      data &&
        data[0] &&
        data[0].encounter &&
        data[0].encounter.serviceProvider &&
        data[0].encounter.serviceProvider.reference &&
        data[0].encounter.serviceProvider.reference._id
        ? data[0].encounter.serviceProvider.reference._id
        : data && data.managingOrganization;
    return orgId ? `${paths.dashboard.org.view(orgId)}` : undefined;
  };

  const getOrganizationTitle = (data, orgOptions) => {
    if (
      data &&
      data[0] &&
      data[0].encounter &&
      data[0].encounter.serviceProvider &&
      data[0].encounter.serviceProvider.reference &&
      data[0].encounter.serviceProvider.reference.name
    ) {
      return data[0].encounter.serviceProvider.reference.name;
    }

    if (data && data.managingOrganization && orgOptions) {
      const org = orgOptions.find((o) => o._id === data.managingOrganization);
      return org ? org.name : undefined;
    }

    return undefined;
  };

  return (
    <>
      {isLoading ? (
        <DashboardContent>
          <CustomBreadcrumbs
            heading="Patient Profile"
            links={[
              { name: 'Dashboard', href: paths.dashboard.root },
              { name: 'Patients', href: paths.dashboard.patient.list },
              {
                name:
                  data && data[0] && data[0].subject.name
                    ? `${data[0].subject.name.given} ${data[0].subject.name.family} `
                    : data.name
                      ? `${data.name.given} ${data.name.family} `
                      : '',
              },
            ]}
            action={
              <>
                <Form methods={methods} onSubmit={handleFilterChange}>
                  <Grid item xs={12}>
                    <Stack
                      direction={{ xs: 'column', sm: 'row' }}
                      py={2}
                      sx={{
                        alignItems: { xs: 'flex-start', sm: 'center' },
                        justifyContent: 'space-between',
                        gap: 2,
                      }}
                    >
                      <Stack
                        direction={'row'}
                        spacing={2}
                        sx={{
                          alignItems: { xs: 'flex-start', sm: 'center' },
                          justifyContent: { xs: 'flex-start', sm: 'space-between' },
                          gap: { xs: 2, sm: 2 },
                        }}
                      >
                        <Controller
                          name="performer"
                          control={methods.control}
                          render={({ field }) => (
                            <TextField
                              {...field}
                              select
                              sx={{ width: { xs: '150px', sm: '300px' } }}
                              label="Practitioner"
                              size="small"
                              onChange={(e) => {
                                field.onChange(e);
                                handleFilterChange({ performer: e.target.value });
                              }}
                              SelectProps={{
                                MenuProps: {
                                  slotProps: {
                                    paper: {
                                      sx: { maxHeight: 220 },
                                    },
                                  },
                                },
                              }}
                            >
                              {practitionerOptions.map((performer) => (
                                <MenuItem key={performer._id} value={performer._id}>
                                  {performer.name.prefix[0]
                                    ? `${performer.name.prefix[0]} ${performer.name.given} ${performer.name.family} `
                                    : `${performer.name.given} ${performer.name.family} `}
                                </MenuItem>
                              ))}
                            </TextField>
                          )}
                        />
                        <StyledDurationFilter
                          onDurationChange={handleDurationChange}
                          resetDuration={true}
                          defaultDuration={payload.duration}
                          minDate={'2024-01-01'}
                          maxDate={dayjs().format('MM-DD-YYYY')}
                        />
                      </Stack>
                    </Stack>
                    <Box sx={{ position: 'fixed', top: 0, left: 0, zIndex: 2001, width: '100%' }}>
                      <LinearProgress color="primary" />
                    </Box>
                  </Grid>
                </Form>
              </>
            }
          />
        </DashboardContent>
      ) : (
        <DashboardContent>
          <CustomBreadcrumbs
            heading="Patient Profile"
            links={[
              { name: 'Dashboard', href: paths.dashboard.root },
              { name: 'Patients', href: paths.dashboard.patient.list },
              {
                name:
                  data && data[0] && data[0].subject.name
                    ? `${data[0].subject.name.given} ${data[0].subject.name.family} `
                    : data.name
                      ? `${data.name.given} ${data.name.family} `
                      : '',
              },
            ]}
            action={
              <>
                <Form methods={methods} onSubmit={handleFilterChange}>
                  <Grid item xs={12}>
                    <Stack
                      direction={{ xs: 'column', sm: 'row' }}
                      py={2}
                      sx={{
                        alignItems: { xs: 'flex-start', sm: 'center' },
                        justifyContent: 'space-between',
                        gap: 2,
                      }}
                    >
                      <Stack
                        direction={'row'}
                        spacing={2}
                        sx={{
                          alignItems: { xs: 'flex-start', sm: 'center' },
                          justifyContent: { xs: 'flex-start', sm: 'space-between' },
                          gap: { xs: 2, sm: 2 },
                        }}
                      >
                        <Controller
                          name="performer"
                          control={methods.control}
                          render={({ field }) => (
                            <TextField
                              {...field}
                              select
                              sx={{ width: { xs: '150px', sm: '300px' } }}
                              label="Practitioner"
                              size="small"
                              onChange={(e) => {
                                field.onChange(e);
                                handleFilterChange({ performer: e.target.value });
                              }}
                              SelectProps={{
                                MenuProps: {
                                  slotProps: {
                                    paper: {
                                      sx: { maxHeight: 220 },
                                    },
                                  },
                                },
                              }}
                            >
                              {practitionerOptions.map((performer) => (
                                <MenuItem key={performer._id} value={performer._id}>
                                  {performer.name.prefix[0]
                                    ? `${performer.name.prefix[0]} ${performer.name.given} ${performer.name.family} `
                                    : `${performer.name.given} ${performer.name.family} `}
                                </MenuItem>
                              ))}
                            </TextField>
                          )}
                        />
                        <StyledDurationFilter
                          onDurationChange={handleDurationChange}
                          resetDuration={true}
                          defaultDuration={payload.duration}
                          minDate={'2024-01-01'}
                          maxDate={dayjs().format('MM-DD-YYYY')}
                        />
                      </Stack>
                    </Stack>
                  </Grid>
                </Form>
              </>
            }
            sx={{ mb: { xs: 1, md: 1 } }}
          />

          <Box
            sx={{ display: 'flex', flex: '1 1 auto', flexDirection: { xs: 'column', lg: 'row' } }}
          >
            <Box
              sx={[
                () => ({
                  gap: 2,
                  display: 'flex',
                  minWidth: { lg: 0 },
                  py: { lg: 3, xl: 5 },
                  flexDirection: 'column',
                  flex: { lg: '1 1 auto' },
                  px: { xl: 5 },
                }),
              ]}
            >
              <Box
                sx={{
                  gap: 3,
                  display: 'grid',
                  gridTemplateColumns: { xs: 'repeat(1, 1fr)', md: 'repeat(3, 1fr)' },
                }}
              >
                <CardSummary
                  title={
                    data && data[0] && data[0].subject.name
                      ? `${data[0].subject.name.given} ${data[0].subject.name.family} `
                      : data.name
                        ? `${data.name.given} ${data.name.family} `
                        : ''
                  }
                  total="Patient"
                  icon={`${CONFIG.assetsDir}/assets/icons/navbar/ic-patient.svg`}
                />

                <CardSummary
                  href={getOrganizationHref(data)}
                  title={getOrganizationTitle(data, orgOptions) ?? '-'}
                  total="Organization"
                  color="success"
                  icon={`${CONFIG.assetsDir}/assets/icons/navbar/ic-banking.svg`}
                />

                <CardSummary
                  title={data && data.length > 0 ? `${data.length} ` : 0}
                  total="In Clinic Visits"
                  color="secondary"
                  icon={`${CONFIG.assetsDir} /assets/icons/navbar/ic-clinical.svg`}
                />
              </Box>

              {data && data.length > 0 ? (
                <ComponentLayout sectionData={SECTION_DATA} />
              ) : (
                <EmptyContent
                  filled
                  sx={[{ py: 10 }]}
                  title={'No In Clinic Visits found. Please try again later.'}
                />
              )}
            </Box>
          </Box>
        </DashboardContent>
      )}
    </>
  );
}

import { Box, Link, Stack, TableCell, TableRow } from '@mui/material';
import IconButton from '@mui/material/IconButton';
import Tooltip from '@mui/material/Tooltip';
import { Iconify } from 'src/components/iconify';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';

// ----------------------------------------------------------------------

export function PatientTableRow({ row, selected, href }) {
  const practitionerName = row.generalPractitioner && row.generalPractitioner.name;
  const organizationName = row.managingOrganization && row.managingOrganization.name;
  const organizationAddress = row.managingOrganization && row.managingOrganization.contact[0];
  const addressLine =
    organizationAddress && organizationAddress.address
      ? `${organizationAddress.address.city}, ${organizationAddress.address.state}-${organizationAddress.address.postalCode}, ${organizationAddress.address.country}`
      : '';

  return (
    <>
      <TableRow hover selected={selected} aria-checked={selected} tabIndex={-1}>
        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ typography: 'body1', flex: '1 1 auto' }}>
              <Link
                component={RouterLink}
                href={href}
                state={{ organization: row }}
                color="inherit"
                sx={{ cursor: 'pointer' }}
              >
                {`${row.name.given} ${row.name.family}`}
              </Link>
            </Stack>
          </Box>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Stack>
            <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
              {dateHelper.formatDate(row.birthDate)}
            </Box>
          </Stack>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Stack>
            <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
              <Link
                component={practitionerName ? RouterLink : 'span'}
                href={
                  practitionerName
                    ? `${paths.dashboard.practitioner.view(row.generalPractitioner._id)}`
                    : undefined
                }
                color="inherit"
                sx={{ cursor: practitionerName ? 'pointer' : 'default' }}
              >
                {practitionerName
                  ? practitionerName.prefix
                    ? `${practitionerName.prefix[0]} ${practitionerName.given} ${practitionerName.family}`
                    : `${practitionerName.given} ${practitionerName.family}`
                  : '-'}
              </Link>
            </Box>
          </Stack>
        </TableCell>

        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body1' }}>
                <Link
                  component={row.managingOrganization ? RouterLink : 'span'}
                  href={
                    row.managingOrganization
                      ? `${paths.dashboard.org.view(row.managingOrganization._id)}`
                      : undefined
                  }
                  color="inherit"
                  sx={{ cursor: row.managingOrganization ? 'pointer' : 'default' }}
                >
                  {organizationName ? `${organizationName}` : '-'}
                </Link>
              </Box>
              <Box
                component="span"
                sx={{ color: themeConfig.palette.grey[700], typography: 'Subtitle2' }}
              >
                {addressLine ? `${addressLine}` : ''}
              </Box>
            </Stack>
          </Box>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ typography: 'body1', flex: '1 1 auto' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {dateHelper.formatDateTime(row.createdAt)}
              </Box>
            </Stack>
          </Box>
        </TableCell>

        <TableCell sx={{ verticalAlign: 'top' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Tooltip title="View Details" placement="top" arrow>
              <IconButton
                component={RouterLink}
                color={themeConfig.palette.grey[700]}
                href={href}
              >
                <Iconify icon="carbon:view-filled" />
              </IconButton>
            </Tooltip>

            <Tooltip title="Quick Notes" placement="top" arrow>
              <IconButton
                color="inherit"
                component={RouterLink}
                href={paths.dashboard.patient.notes(row._id)}
                state={{ details: `${row.name.given} ${row.name.family}` }}
                onClick={() => {
                  localStorage.setItem(
                    'note-details',
                    JSON.stringify(`${row.name.given} ${row.name.family}`)
                  );
                }}
              >
                <Iconify icon="streamline-cyber:pencil-clipboard" />
              </IconButton>
            </Tooltip>
          </Box>
        </TableCell>
      </TableRow>
    </>
  );
}

import {
  Timeline,
  TimelineConnector,
  TimelineContent,
  TimelineDot,
  TimelineItem,
  TimelineOppositeContent,
  TimelineSeparator,
} from '@mui/lab';
import { Box, Paper, Typography } from '@mui/material';
import { varAlpha } from 'minimal-shared/utils';
import { Iconify } from 'src/components/iconify';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';

export default function PatientTimelineView({ data }) {
  return (
    <Timeline position="alternate">
      {data.map((item) => (
        <TimelineItem key={item.key}>
          <TimelineOppositeContent>
            <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }}>
              {dateHelper.formatDateTime(item.createdAt)}
            </Typography>
          </TimelineOppositeContent>
          <TimelineSeparator>
            <TimelineDot color="info">
              {<Iconify width={24} icon="fa6-solid:hospital-user" />}
            </TimelineDot>
            <TimelineConnector />
          </TimelineSeparator>
          <TimelineContent>
            <Paper
              sx={[
                (theme) => ({
                  p: 3,
                  bgcolor: varAlpha(theme.vars.palette.grey['500Channel'], 0.12),
                }),
              ]}
            >
              <Typography variant="body2" color="text.primary">
                <strong>
                  {item && item.performer && item.performer.name
                    ? (item.performer.name.prefix &&
                      Array.isArray(item.performer.name.prefix) &&
                      item.performer.name.prefix[0]
                      ? `${item.performer.name.prefix[0]} ${item.performer.name.given || ''} ${item.performer.name.family || ''}`
                      : `${item.performer.name.given || ''} ${item.performer.name.family || ''}`
                    ).trim()
                    : ' '}
                </strong>
              </Typography>

              <Typography variant="body2">
                <strong>Organization:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.encounter &&
                    item.encounter.serviceProvider &&
                    item.encounter.serviceProvider.reference
                    ? `${item.encounter.serviceProvider.reference.name}`
                    : '-'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Puck :</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item && item.encounter && item.encounter.basedOn
                    ? `${item.encounter.basedOn}`
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Implant:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item && item.encounter && item.encounter.device
                    ? `${item.encounter.device}`
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Clinician App:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item && item.encounter && item.encounter.kioskId
                    ? `${item.encounter.kioskId}`
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Start Time :</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.effectivePeriod && item.effectivePeriod.start
                    ? dateHelper.formatDateTime(item.effectivePeriod.start)
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>End Time :</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.effectivePeriod && item.effectivePeriod.end
                    ? dateHelper.formatDateTime(item.effectivePeriod.end)
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Duration:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.effectivePeriod && item.effectivePeriod.start && item.effectivePeriod.end
                    ? dateHelper.getTimeDuration(
                      item.effectivePeriod.start,
                      item.effectivePeriod.end
                    )
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Total ICP Studies:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.totalIcpStudies === 0 ? 1 : item.totalIcpStudies}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Note:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.note && item.note[0] && item.note[0].authorString
                    ? `${item.note[0].authorString}`
                    : ' -'}
                </Box>
              </Typography>
            </Paper>
          </TimelineContent>
        </TimelineItem>
      ))}
    </Timeline>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { Box, Button, InputAdornment } from '@mui/material';
import Grid from '@mui/material/Grid2';
import { useCallback, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { Field, Form } from 'src/components/hook-form';
import { Iconify } from 'src/components/iconify';
import { z as zod } from 'zod';

// ----------------------------------------------------------------------

export const PractitionerSchema = zod.object({
  search: zod.string().optional(),
});

export function PractitionerDetailToolbar({ filters, onFilterChange, onResetPage }) {
  const methods = useForm({
    mode: 'onSubmit',
    resolver: zodResolver(PractitionerSchema),
    defaultValues: filters.state,
  });

  const { handleSubmit, reset, watch } = methods;
  const searchValue = watch('search');

  const onFilterClick = useCallback(
    handleSubmit(async (data) => {
      onResetPage();
      onFilterChange(data);
    }),
    [onResetPage, onFilterChange, handleSubmit]
  );

  useEffect(() => {
    if (filters.state.search === '') {
      reset({ search: '' });
    }
  }, [filters.state.search, reset]);

  return (
    <Form methods={methods} onSubmit={onFilterClick}>
      <Box sx={{ p: 2.5 }}>
        <Grid container spacing={2}>
          <Grid size={{ xs: 8, sm: 10, md: 10.5, lg: 10.8 }}>
            <Field.Text
              name="search"
              type="search"
              placeholder="Search by Patient"
              size="small"
              slotProps={{
                htmlInput: { maxLength: 50 },
                input: {
                  startAdornment: (
                    <InputAdornment position="start">
                      <Iconify icon="eva:search-fill" sx={{ color: 'text.disabled' }} />
                    </InputAdornment>
                  ),
                },
              }}
            />
          </Grid>

          <Grid size={{ xs: 4, sm: 2, md: 1.5, lg: 1.2 }}>
            <Button
              type="submit"
              color="primary"
              fullWidth
              variant="contained"
              startIcon={<Iconify icon="eva:search-fill" />}
            >
              Search
            </Button>
          </Grid>
        </Grid>
      </Box>
    </Form>
  );
}

