const STUDY_OPTIONS_List = [{ value: '', label: 'All' }, ...Study_Status];

const TABLE_HEAD = [
  { id: 'createdAt', label: 'Encounter Date', width: '20%' },
  { id: 'subject.name', label: 'Patient', width: '20%' },
  { id: 'serviceProvider.name', label: 'Organization', width: '22%' },
  { id: 'serviceProvider.name', label: 'Address', width: '25%', sortBy: false },
  { id: 'status', label: 'Status', width: '13%', sortBy: false },
  { label: 'Action', width: '10%', sortBy: false, sx: { paddingLeft: '30px' } },
];

export function PractitionerDetailView() {
  const { _id } = useParams();
  const table = useTable();
  const [isLoading, setIsLoading] = useState(false);
  const [data, setData] = useState([]);
  const [tableData, setTableData] = useState([]);
  const filters = useSetState({ serviceType: '', search: '' });

  const { state: currentFilters, setState: updateFilters } = filters;

  const [payload, setPayload] = useState({
    _id: _id,
    duration: enums.Duration.TwelveMonths,
    startDate: null,
    endDate: null,
    timezone: dateHelper.getCurrentTimeZone(),
    serviceType: null,
    sortBy: 'createdAt',
    sortDirection: 'desc',
  });

  useEffect(() => {
    if (payload.duration === enums.Duration.Between) {
      if (!payload.startDate || !payload.endDate) {
        return;
      }
    }
    getPatientDetail();
  }, [payload]);

  const getPatientDetail = async () => {
    setIsLoading(true);
    if (payload._id) {
      const response = await apiService.getPractitionerDetailAsync(payload);
      const { data } = response;
      setData(data);
      setTableData(data.getEncounterList);
    }
    setIsLoading(false);
  };

  const handleFilterChange = (filterDetail) => {
    const { search, serviceType, ...apiFilters } = filterDetail;

    updateFilters({
      search: search || '',
      serviceType: serviceType || '',
      ...apiFilters,
    });

    if (!search) {
      setPayload((prev) => ({
        ...prev,
        ...apiFilters,
      }));
    }
  };

  const handleDurationChange = (duration, start, end) => {
    if (duration === enums.Duration.Between) {
      setPayload((prevState) => ({
        ...prevState,
        duration,
        startDate: start,
        endDate: end,
      }));
    } else {
      setPayload((prevState) => ({
        ...prevState,
        duration,
        startDate: null,
        endDate: null,
      }));
    }
  };

  const dataFiltered = applyFilter({
    inputData: tableData,
    comparator: getComparator(table.order, table.orderBy),
    filters: currentFilters,
  });
  const methods = useForm({
    defaultValues: payload,
  });

  const canReset = currentFilters.search !== '' || currentFilters.serviceType !== '';
  const notFound = (!dataFiltered.length && canReset) || !dataFiltered.length;

  const handleFilterType = useCallback(
    (event, newValue) => {
      table.onResetPage();
      updateFilters({ serviceType: newValue });
    },
    [updateFilters, table]
  );

  const handleSort = (property) => {
    const newOrder = table.orderBy === property && table.order === 'asc' ? 'desc' : 'asc';
    table.setOrder(newOrder);
    table.setOrderBy(property);
    setPayload((prev) => ({
      ...prev,
      sortBy: property,
      sortDirection: newOrder,
    }));
  };

  return (
    <>
      <DashboardContent >
        <CustomBreadcrumbs
          heading="Practitioner Profile"
          links={[
            { name: 'Dashboard', href: paths.dashboard.root },
            { name: 'Practitioners', href: paths.dashboard.practitioner.list },
            { name: data ? data.name : '' },
          ]}
          sx={{ mb: { xs: 1, md: 1 } }}
          action={
            <>
              <Form methods={methods} onSubmit={handleFilterChange}>
                <Grid item xs={12}>
                  <Stack
                    py={2}
                    direction={{ xs: 'column', sm: 'row' }}
                    sx={{
                      alignItems: { xs: 'flex-start', sm: 'center' },
                      justifyContent: 'space-between',
                      gap: 2,
                    }}
                  >
                    <Stack
                      spacing={2}
                      direction={'row'}
                      sx={{
                        gap: { xs: 2, sm: 2 },
                        alignItems: { xs: 'flex-start', sm: 'center' },
                        justifyContent: { xs: 'flex-start', sm: 'space-between' },
                      }}
                    >
                      <StyledDurationFilter
                        onDurationChange={handleDurationChange}
                        resetDuration={true}
                        defaultDuration={payload.duration}
                        minDate={'2024-01-01'}
                        maxDate={dayjs().format('MM-DD-YYYY')}
                      />
                    </Stack>
                  </Stack>
                  {/* <Box sx={{ position: 'fixed', top: 0, left: 0, zIndex: 2001, width: '100%' }}>
                    <LinearProgress color="primary" />
                  </Box> */}
                </Grid>
              </Form>
            </>
          }
        />

        <Grid container spacing={3}>
          <Grid size={{ xs: 12, md: 4 }}>
            <CardSummary
              title={data ? data.email : ''}
              total={data ? data.code : ''}
              icon={`${CONFIG.assetsDir}/assets/icons/navbar/ic-doctor.svg`}
            />
          </Grid>

          <Grid size={{ xs: 12, md: 4 }}>
            <CardSummary
              href={`${paths.dashboard.org.view(data.organization)}`}
              title={data && data.orgName ? data.orgName : ''}
              total="Organization"
              color="secondary"
              icon={`${CONFIG.assetsDir}/assets/icons/navbar/ic-banking.svg`}
            />
          </Grid>

          <Grid size={{ xs: 12, md: 4 }}>
            <CardSummary
              title={
                data && data.getPatientStatistics && data.getPatientStatistics.totalPatients
                  ? data.getPatientStatistics.totalPatients
                  : 0
              }
              total="Patients"
              color="success"
              icon={`${CONFIG.assetsDir}/assets/icons/navbar/ic-patient.svg`}
            />
          </Grid>

          <Grid size={{ xs: 12, md: 12 }}>
            <Card>
              <Tabs
                value={currentFilters.serviceType}
                onChange={handleFilterType}
                sx={[
                  (theme) => ({
                    px: 2.5,
                    boxShadow: `inset 0 -2px 0 0 ${varAlpha(theme.vars.palette.grey['500Channel'], 0.08)}`,
                  }),
                ]}
              >
                {STUDY_OPTIONS_List.map((tab) => (
                  <Tab
                    key={tab.value}
                    iconPosition="end"
                    value={tab.value}
                    label={tab.label}
                    icon={
                      <Label
                        variant={
                          ((tab.value === '' || tab.value === currentFilters.serviceType) &&
                            'filled') ||
                          'soft'
                        }
                        color={
                          (tab.value === 'Home Study' && 'success') ||
                          (tab.value === 'Clinical Study' && 'warning') ||
                          'default'
                        }
                      >
                        {['Home Study', 'Clinical Study'].includes(tab.value)
                          ? tableData.filter((data) => data.serviceType.coding.code === tab.value)
                            .length
                          : tableData.length}
                      </Label>
                    }
                  />
                ))}
              </Tabs>

              <PractitionerDetailToolbar
                filters={filters}
                onFilterChange={handleFilterChange}
                onResetPage={table.onResetPage}
              />

              {canReset && (
                <PractitionerDetailFiltersResult
                  filters={filters}
                  totalResults={dataFiltered.length}
                  onResetPage={table.onResetPage}
                  sx={{ p: 2.5, pt: 0 }}
                />
              )}

              <Box sx={{ position: 'relative' }}>
                <TableSelectedAction
                  dense={table.dense}
                  numSelected={table.selected.length}
                  rowCount={dataFiltered.length}
                  onSelectAllRows={(checked) =>
                    table.onSelectAllRows(
                      checked,
                      dataFiltered.map((row) => row.id)
                    )
                  }
                />

                <Paper sx={{ width: '100%', overflow: 'hidden' }}>
                  <TableContainer sx={{ height: 'calc(100vh - 46vh)' }}>
                    <Box sx={{ position: 'relative' }}>
                      <Table
                        stickyHeader={true}
                        aria-label="sticky table"
                        size={table.dense ? 'small' : 'medium'}
                        sx={{ minWidth: 960 }}
                      >
                        <TableHeadCustom
                          order={table.order}
                          orderBy={table.orderBy}
                          headCells={TABLE_HEAD}
                          rowCount={tableData.length}
                          numSelected={table.selected.length}
                          onSort={handleSort}
                        />

                        {isLoading ? (
                          <TableBody>
                            <TableRow>
                              <TableCell colSpan={TABLE_HEAD.length}>
                                <Box
                                  sx={{
                                    display: 'flex',
                                    justifyContent: 'center',
                                    alignItems: 'center',
                                    height: '100%',
                                    width: '100%',
                                  }}
                                >
                                  <Stack alignItems="center" justifyContent="center" sx={{ width: '100%' }}>
                                    <LinearProgress color="inherit" sx={{ width: '50%', maxWidth: 360 }} />
                                  </Stack>
                                </Box>
                              </TableCell>
                            </TableRow>
                          </TableBody>
                        ) : (
                          <TableBody>
                            {dataFiltered
                              .slice(
                                table.page * table.rowsPerPage,
                                table.page * table.rowsPerPage + table.rowsPerPage
                              )
                              .map((row) => (
                                <ClinicalVisitTableRow
                                  key={row.id}
                                  row={row}
                                  selected={table.selected.includes(row.id)}
                                  onSelectRow={() => table.onSelectRow(row.id)}
                                  isPractitionerView={true}
                                />
                              ))}
                            <TableEmptyRows
                              height={table.dense ? 56 : 56 + 20}
                              emptyRows={emptyRows(
                                table.page,
                                table.rowsPerPage,
                                dataFiltered.length
                              )}
                            />
                            <TableNoData
                              label="No records found. Please try again later or adjust your search."
                              notFound={notFound}
                            />
                          </TableBody>
                        )}
                      </Table>
                    </Box>
                  </TableContainer>
                  <TablePaginationCustom
                    page={table.page}
                    dense={table.dense}
                    count={dataFiltered.length}
                    rowsPerPage={table.rowsPerPage}
                    onPageChange={table.onChangePage}
                    onChangeDense={table.onChangeDense}
                    onRowsPerPageChange={table.onChangeRowsPerPage}
                  />
                </Paper>
              </Box>
            </Card>
          </Grid>
        </Grid>
      </DashboardContent >

    </>
  );
}

function applyFilter({ inputData, comparator, filters }) {
  const { search, serviceType } = filters;

  const stabilizedThis = inputData.map((el, index) => [el, index]);
  stabilizedThis.sort((a, b) => {
    const order = comparator(a[0], b[0]);
    if (order !== 0) return order;
    return a[1] - b[1];
  });

  let filteredData = stabilizedThis.map((el) => el[0]);

  if (serviceType) {
    filteredData = filteredData.filter((data) => data.serviceType?.coding?.code === serviceType);
  }

  if (search) {
    const searchTerms = search.toLowerCase().split(/\s+/).filter(term => term.length > 0);

    filteredData = filteredData.filter(data => {
      const name = data.subject?.name;
      if (!name) return false;

      const given = name.given?.toLowerCase() || '';
      const family = name.family?.toLowerCase() || '';
      const prefix = Array.isArray(name.prefix)
        ? name.prefix.map(p => p.toLowerCase()).join(' ')
        : name.prefix?.toLowerCase() || '';

      const nameComponents = [
        ...given.split(/\s+/),
        ...family.split(/\s+/),
        ...prefix.split(/\s+/)
      ].filter(comp => comp.length > 0);

      return searchTerms.every(term =>
        nameComponents.some(comp => comp.includes(term))
      );
    });
  }

  return filteredData;
}

