                    localStorage.setItem(
                      'note-details',
                      JSON.stringify(`${row.practitioner.display}`)
                    );
                  }}
                >
                  <Iconify icon="streamline-cyber:pencil-clipboard" />
                </IconButton>
              </Tooltip>

              <Tooltip title="Quick Delete" placement="top" arrow>
                <IconButton color="error" onClick={() => confirmDialog.onTrue()}>
                  <Iconify icon="solar:trash-bin-trash-bold" />
                </IconButton>
              </Tooltip>
            </Box>
          </TableCell>
        )}
      </TableRow>

      {renderConfirmDialog()}
      {renderSetHours()}
    </>
  );
}

