import { Iconify } from 'src/components/iconify';
import { themeConfig } from 'src/theme';
import dateHelper from 'src/utils/dateHelper';

export default function PractitionerTimelineView({ data }) {
  return (
    <Timeline position="alternate">
      {data.map((item) => (
        <TimelineItem key={item.key}>
          <TimelineOppositeContent>
            <Typography variant="body2" sx={{ color: themeConfig.palette.grey[700] }}>
              {dateHelper.formatDateTime(item.createdAt)}
            </Typography>
          </TimelineOppositeContent>
          <TimelineSeparator>
            <TimelineDot color="info">
              {<Iconify width={24} icon="fa6-solid:hospital-user" />}
            </TimelineDot>
            <TimelineConnector />
          </TimelineSeparator>
          <TimelineContent>
            <Paper
              sx={[
                (theme) => ({
                  p: 3,
                  bgcolor: varAlpha(theme.vars.palette.grey['500Channel'], 0.12),
                }),
              ]}
            >
              <Typography variant="body2" color="text.primary">
                <strong>
                  {item && item.subject && item.subject.name
                    ? `${item.subject.name.given || ''} ${item.subject.name.family || ''}`
                    : ' '}
                </strong>
              </Typography>

              <Typography variant="body2">
                <strong>Organization:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.serviceProvider && item.serviceProvider.reference
                    ? `${item.serviceProvider.reference.name}`
                    : '-'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Type:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item &&
                    item.serviceType &&
                    item.serviceType.coding &&
                    item.serviceType.coding.code
                    ? item.serviceType.coding.code === 'Clinical Study'
                      ? 'In Clinic Visit'
                      : item.serviceType.coding.code
                    : '-'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Puck :</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item && item.basedOn ? `${item.basedOn}` : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>Implant:</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item && item.device ? `${item.device}` : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                {item && item.kioskId ? (
                  <>
                    <strong>Clinician App:</strong>{' '}
                    <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                      {item && item.kioskId ? `${item.kioskId}` : ' -'}
                    </Box>
                  </>
                ) : (
                  <>
                    <strong>Patient App:</strong>{' '}
                    <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                      {item && item.mobileId ? `${item.mobileId}` : ' -'}
                    </Box>
                  </>
                )}
              </Typography>

              <Typography variant="body2">
                <strong>Start Time :</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.period && item.period.start
                    ? dateHelper.formatDateTime(item.period.start)
                    : ' -'}
                </Box>
              </Typography>

              <Typography variant="body2">
                <strong>End Time :</strong>{' '}
                <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                  {item.period && item.period.end
                    ? dateHelper.formatDateTime(item.period.end)
                    : ' -'}
                </Box>
              </Typography>

              {item && item.period && item.period.start && item.period.end ? (
                <>
                  <Typography variant="body2">
                    <strong>Duration:</strong>{' '}
                    <Box component="span" sx={{ color: themeConfig.palette.grey[700] }}>
                      {item.period && item.period.start && item.period.end
                        ? dateHelper.getTimeDuration(item.period.start, item.period.end)
                        : ' -'}
                    </Box>
                  </Typography>
                </>
              ) : null}
            </Paper>
          </TimelineContent>
        </TimelineItem>
      ))}
    </Timeline>
  );
}

